  } else if (msg.location && msg.location.latitude !== undefined && msg.location.longitude !== undefined) {
    const lat = msg.location.latitude;
    const lon = msg.location.longitude;

    mensaje = `fichar ubicacion: ${lat}, ${lon}`;
    tieneImagen = true;

    imgData = {
      kind: 'location',
      latitude: lat,
      longitude: lon,
      horizontal_accuracy: msg.location.horizontal_accuracy || null,
      heading: msg.location.heading || null,
