      message_date_unix: msg.date || null,
      timestamp: nowIso(),
      from_chat_id: chatId,
      from_user_id: userId,
    };
  } else {
    mensaje = '[Mensaje no soportado]';
  }

  return {
    plataforma: 'telegram',
    canal_respuesta: 'telegram',

    mensaje_usuario: mensaje,
    chat_id: chatId,
    user_id: userId,
    user_name: userName,
