    };
  } else if (tipo === 'document') {
    mensaje = waMsg.document?.caption?.trim() || '[Documento recibido]';
    fileId = waMsg.document?.id || null;
  } else if (tipo === 'location' && waMsg.location?.latitude !== undefined && waMsg.location?.longitude !== undefined) {
