async function firstExistingAnalyticLineId(uid, orderedIds) {
  const uniq = [];
  const seen = new Set();
  for (const raw of orderedIds) {
    const id = Number(raw);
    if (!Number.isFinite(id) || id <= 0 || seen.has(id)) continue;
    seen.add(id);
    uniq.push(id);
  }
  if (!uniq.length) return null;
  const sr = await http({
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
