        'search_read',
        [[['id', 'in', uniq]]],
        { fields: ['id'], limit: 200 },
      ],
    },
    id: 60,
  });
  const found = new Set((Array.isArray(sr?.result) ? sr.result : []).map((r) => Number(r.id)));
  for (const id of uniq) {
    if (found.has(id)) return id;
  }
  return null;
}

function odooUtcSinceMinutes(min) {
  const d = new Date(Date.now() - min * 60000);
  return d.toISOString().replace('T', ' ').slice(0, 19);
}

