  // --- Crear productos faltantes (tras confirmación) ---
  if (x.compra_inv_ejecutar_crear === true) {
    let resueltos = Array.isArray(memDp.productos_resueltos) ? [...memDp.productos_resueltos] : [];
    const falt = Array.isArray(memDp.productos_faltantes) ? memDp.productos_faltantes : [];
    const creados = [];
    for (const f of falt) {
