      }
    }
    const dpNext = {
      items: memDp.items || [],
      productos_resueltos: resueltos,
      productos_faltantes: [],
    };
    const lista = resueltos.map((p) => `• ${p.nombre} x${p.cantidad}`).join('\n');
    const extra = creados.length ? `\n\n✅ Productos nuevos en catálogo: ${creados.join(', ')}` : '';
    return {
      ...baseOut,
      respuesta_usuario:
        `📦 Registrado en catálogo:\n${lista}${extra}\n\n¿Quieres *vincular* estos materiales al *último parte de trabajo*? (sí / no)`,
      esperando_confirmacion: 'compra_inv_pregunta_vincular',
      datos_pendientes: JSON.stringify(dpNext),
      accion: 'conversar',
    };
  }

  // --- Vincular al último parte ---
  if (x.compra_inv_vincular_si === true) {
    const resueltos = Array.isArray(memDp.productos_resueltos) ? memDp.productos_resueltos : [];
    const tsId = await resolverTimesheetVincular(uid, x);
    if (!tsId) {
      return {
