          '❌ No encontré tu último parte de horas en Odoo (usuario o parte). Los productos siguen solo en catálogo.',
        accion: 'conversar',
        limpiar_confirmacion_compra_inv: true,
        borrar_memoria: true,
      };
    }
    let ok = [];
    let fallos = [];
    try {
      ok = await agregarMaterialesAlParteViaWrite(uid, tsId, resueltos);
    } catch (e) {
      fallos.push(e.message || String(e));
    }
    if (!ok.length && fallos.length) {
      return {
        ...baseOut,
        respuesta_usuario:
          `❌ No pude añadir materiales al parte ID ${tsId} (Odoo). Revisa el parte en la pestaña «Productos utilizados».\n` +
          fallos.map((l) => '• ' + l).join('\n'),
        accion: 'conversar',
        limpiar_confirmacion_compra_inv: true,
        borrar_memoria: true,
      };
    }
    const msg =
      `✅ Materiales añadidos al parte ID ${tsId} (líneas en «Productos utilizados» del timesheet).\n` +
      ok.map((l) => '• ' + l).join('\n');
    return {
      ...baseOut,
      respuesta_usuario: msg,
      accion: 'conversar',
      limpiar_confirmacion_compra_inv: true,
      borrar_memoria: true,
    };
  }

  // --- Flujo inicial: buscar en catálogo ---
  let items = normItems(x.items);
  if (items.length === 0) items = normItems(memDp.items);
  if (items.length === 0) {
    return {
