const x = $json;
const chatId = x.chat_id;

const asStr = (v) => (v == null ? '' : String(v).trim());
const asNum = (v, d = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};

const norm = (s) =>
  String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const isDiagnosis = !!x.is_diagnosis_task;

const ticketType = norm(x.ticket_type);
const isNuevaInstalacion =
  ticketType === 'nueva instalacion' ||
  ticketType === 'nueva_instalacion' ||
  ticketType.includes('nueva instalacion') ||
  ticketType === 'instalacion' ||
  ticketType.includes('instalacion');

const horasPresup = asNum(x.horas_presupuestadas, 0);

// 🔍 Intentar obtener productos validados desde el nodo de validación
let productosValidados = [];
try {
  const validacionResult = $('Validar Productos FSM')?.item?.json;
  if (validacionResult && Array.isArray(validacionResult.productos_validados)) {
    productosValidados = validacionResult.productos_validados;
    console.log('✅ Productos validados encontrados:', productosValidados.length);
  }
} catch (e) {
  console.log('⚠️ No se encontraron productos validados, usando productos originales');
}

const productos =
  productosValidados.length > 0
    ? productosValidados
    : (Array.isArray(x.productos) ? x.productos : []);

// ✅ Ahora sí: inicializa items primero
const items = productos
  .map((p) => ({
    nombre: asStr(p.product_name || p.nombre),
    cantidad: asNum(p.quantity || p.cantidad, 1),
    product_id: p.product_id || false,
    notes: asStr(p.notes || ''), // opcional
  }))
  .filter((p) => p.nombre);

// ✅ Y DESPUÉS metes la línea de presupuesto si aplica
if (isDiagnosis && horasPresup > 0) {
  items.push({
    nombre: 'Horas presupuestadas',
    cantidad: horasPresup,
    product_id: false,
    notes: 'Estimación / Presupuesto (diagnóstico/presupuesto)',
  });
}

console.log('📦 Productos normalizados:', items);

// Proyecto FSM por defecto
const proyecto = asStr(x.proyecto) || 'Servicio de campo';
const tareaSugerida =
  asStr(x.tarea) || `Intervención - ${new Date().toLocaleDateString('es-ES')}`;

const authUid = Number($('Autenticar Odoo')?.item?.json?.result);
let uid = Number(x.uid);
if (!Number.isFinite(uid) || uid < 1 || String(x.uid ?? '').toLowerCase() === 'unknown') {
  uid = Number.isFinite(authUid) && authUid >= 1 ? authUid : 2;
}
const db = x.db || 'lsanchezgoshawk-botpartesdetrabajo-main-32341811';

const odoo_user = asStr(x.odoo_user || x.cliente_perfil?.email || '');
const odoo_user_id = x.odoo_user_id || x.cliente_perfil?.user_id || null;

const transcripcion_original = asStr(
  x.transcripcion_original || x.mensaje_usuario_original || x.mensaje_original || ''
);
const mensaje_usuario_original = asStr(x.mensaje_usuario_original || x.mensaje_original || '');

const contextoKey = `memoria_${chatId}`;
let memoria = global[contextoKey] || {};

const parteEnMemoria = {
  horas: asNum(x.horas, 0),
  descripcion: asStr(x.descripcion) || 'Trabajo realizado',
  productos: items,
  cliente: asStr(x.cliente || ''),
  proyecto_sugerido: proyecto,
  tarea_sugerida: tareaSugerida,
  transcripcion_original,
  timestamp: new Date().toISOString(),
  ticket_type: x.ticket_type || '',
  horas_presupuestadas: horasPresup,
  is_diagnosis_task: isDiagnosis,
  travel_distance_km: asNum(x.travel_distance_km, 0),
  travel_time_hours: asNum(x.travel_time_hours, 0),
};

memoria.parte_en_registro = parteEnMemoria;
memoria.esperando_confirmacion = 'elegir_tarea_calendario';
global[contextoKey] = memoria;

return {
  proyecto,
  tarea: tareaSugerida,
  horas: asNum(x.horas, 0),
  descripcion: asStr(x.descripcion) || 'Trabajo realizado',
  productos: items,
  cliente: asStr(x.cliente || ''),
  is_diagnosis_task: isDiagnosis,
  ticket_type: x.ticket_type || '',
  horas_presupuestadas: horasPresup,
  odoo_user,
  odoo_user_id,
  transcripcion_original,
  mensaje_usuario_original,
  parte_en_memoria: parteEnMemoria,
  db,
  uid,
  chat_id: x.chat_id,
  travel_distance_km: asNum(x.travel_distance_km, 0),
  travel_time_hours: asNum(x.travel_time_hours, 0),
  plataforma: x.plataforma || 'telegram',
  canal_respuesta: x.plataforma || 'telegram',

};

// REGISTRAR MATERIALES (robusto en esta rama)
// - timesheet_line_id SIEMPRE se lee de "HTTP Registrar Horas Directo FSM"
// - productos se leen con prioridad: input validados > Validar Productos1 validados > input productos/datos_parte > seed Registrar Tarea Odoo > pendientes > reg > normalizar
// ✅ CORRECCION: las "horas_presupuestadas" NO son materiales (no deben entrar en account.analytic.line.product)

const firstJson = (nodeName) => {
  try { return $items(nodeName, 0)?.[0]?.json ?? null; } catch { return null; }
};

const parseMaybeJson = (v) => {
  if (!v) return null;
  if (typeof v === 'object') return v;
  if (typeof v === 'string') {
    try { return JSON.parse(v); } catch { return null; }
  }
  return null;
};

// ✅ 1) timesheet_line_id (robusto para rama normal + corrección productos)
// Prioridad: input -> Registro (Registrar Horas Directo FSM) -> memoria -> HTTP

const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const httpHoras = firstJson('HTTP Registrar Horas Directo FSM') || {};
const regNodeWrap = firstJson('Registrar Horas Directo FSM') || {};
const reg = regNodeWrap.registro || regNodeWrap || {};

const memRow = firstJson('Preparar Datos AI Agent') || {};
const pendientesMem = parseMaybeJson(memRow?.datos_pendientes) || {};

// ✅ 2) contexto

const norm = firstJson('Normalizar Parte+Materiales FSM') || {};
const auth = firstJson('Autenticar Odoo') || {};

// ⚠️ validador (según ramas)
const valid =
  firstJson('Validar Productos1') ||
  firstJson('Validar Productos FSM') ||
  {};

// ✅ seed del nodo Registrar Tarea Odoo (donde a menudo está el producto correcto estructurado)
const seed = firstJson('Registrar Tarea Odoo') || {};
const seedParte = seed.datos_parte || {};

// memoria postgres (si existe)
const dpObj =
  parseMaybeJson($json.datos_pendientes) ||
  parseMaybeJson($json.datos_pendientes_json) ||
  $json.datos_pendientes ||
  null;

// --- contexto mínimo para nodos posteriores (Limpiar / material FSM) ---
const __ctxOut = (extra = {}) => {
  const tid =
    reg.task_id ??
    reg.tarea_id ??
    $json.task_id ??
    $json.tarea_id ??
    seed.datos_registrados?.task_id ??
    seed.tarea_id ??
    null;
  return {
    ...reg,
    ...($json || {}),
    task_id: tid,
    tarea_id: tid,
    chat_id: reg.chat_id ?? $json.chat_id ?? memRow?.chat_id ?? null,
    db: reg.db ?? $json.db ?? norm.db ?? 'lsanchezgoshawk-botpartesdetrabajo-main-32341811',
    uid: reg.uid ?? $json.uid ?? norm.uid ?? 2,
    datos_parte:
      $json.datos_parte ??
      pendientesMem?.datos_parte ??
      seedParte ??
      null,
    transcripcion_original:
      reg.transcripcion_original ??
      reg.transcripcion_real ??
      pendientesMem?.datos_parte?.transcripcion_original ??
      pendientesMem?.datos_parte?.mensaje_usuario_original ??
      seedParte?.transcripcion_original ??
      seedParte?.mensaje_usuario_original ??
      $json.transcripcion_original ??
      $json.mensaje_usuario_original ??
      (String(memRow?.mensaje_usuario || '').length > 15 &&
      !/^[0-9]{1,3}$/.test(String(memRow.mensaje_usuario).trim())
        ? memRow.mensaje_usuario
        : null) ??
      null,
    mensaje_usuario_original:
      reg.mensaje_usuario_original ??
      pendientesMem?.datos_parte?.mensaje_usuario_original ??
      pendientesMem?.datos_parte?.transcripcion_original ??
      seedParte?.mensaje_usuario_original ??
      $json.mensaje_usuario_original ??
      null,
    odoo_user: reg.odoo_user ?? pendientesMem.odoo_user ?? $json.odoo_user ?? null,
    ...extra,
  };
};

let timesheetLineId =
  toNum($json.timesheet_line_id) ||
  toNum(reg.timesheet_line_id) ||
  toNum(pendientesMem.timesheet_line_id) ||
  (() => {
    let raw =
      httpHoras.result ??
      httpHoras.body?.result ??
      httpHoras.json?.result ??
      null;
    if (Array.isArray(raw)) raw = raw[0];
    return toNum(raw);
  })();

if (!timesheetLineId || timesheetLineId <= 0) {
  return __ctxOut({
    skip_materiales: true,
    motivo: 'Sin timesheet_line_id (input/registro/memoria/HTTP)',
    timesheet_line_id: timesheetLineId || null,
    debug_timesheet_sources: {
      input: $json.timesheet_line_id ?? null,
      reg: reg.timesheet_line_id ?? null,
      mem: pendientesMem.timesheet_line_id ?? null,
      http_has_item: !!firstJson('HTTP Registrar Horas Directo FSM'),
    },
  });
}

// ✅ 3) productos (PRIORIDAD CORREGIDA)
let productos = [];

// 0) input actual ya trae validados (p.ej. vienes de la corrección/validación)
if (Array.isArray($json.productos_validados) && $json.productos_validados.length) {
  productos = $json.productos_validados;

// ✅ 0.1) lo que dejó "Validar Productos1" (VALORES YA CON product_id) → PRIORIDAD MUY ALTA
} else if (Array.isArray(valid.productos_validados) && valid.productos_validados.length) {
  productos = valid.productos_validados;

// 0.2) input actual trae productos ya estructurados (corrección parseada)
} else if (Array.isArray($json.productos) && $json.productos.length) {
  productos = $json.productos;

// 0.3) o dentro del input datos_parte
} else if (Array.isArray($json.datos_parte?.productos) && $json.datos_parte.productos.length) {
  productos = $json.datos_parte.productos;

// 0.4) seed de “Registrar Tarea Odoo”
} else if (Array.isArray(seedParte.productos) && seedParte.productos.length) {
  productos = seedParte.productos;

// 0.5) datos_pendientes.datos_parte.productos
} else if (Array.isArray(dpObj?.datos_parte?.productos) && dpObj.datos_parte.productos.length) {
  productos = dpObj.datos_parte.productos;

// 0.6) fallback registro original (a veces viene “mal escrito” aquí)
} else if (Array.isArray(reg.productos) && reg.productos.length) {
  productos = reg.productos;

// 0.7) fallback normalizado
} else if (Array.isArray(norm.productos) && norm.productos.length) {
  productos = norm.productos;
}

// ✅ 3b) FILTRAR: quitar "Horas presupuestadas" (no son materiales)
const normText = (s) =>
  String(s ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const isPresupuestoItem = (p) => {
  const name = normText(p?.product_name || p?.nombre || p?.notes || '');
  const notes = normText(p?.notes || '');

  const byName =
    name.includes('hora presupuestada') ||
    name.includes('horas presupuestadas') ||
    name === 'horas' ||
    name.includes('presupuesto') ||
    name.includes('estimacion') ||
    name.includes('estimación');

  const byNotes =
    notes.includes('presupuesto') ||
    notes.includes('estimacion') ||
    notes.includes('estimación');

  const pid = p?.product_id;
  const pidNum = Array.isArray(pid) ? Number(pid[0]) : Number(pid);
  const noPid = !Number.isFinite(pidNum) || pidNum <= 0;

  return (
    byName ||
    byNotes ||
    (noPid && name.includes('horas') && (name.includes('presup') || name.includes('estim')))
  );
};

if (Array.isArray(productos) && productos.length) {
  productos = productos.filter((p) => !isPresupuestoItem(p));
}

if (!Array.isArray(productos) || productos.length === 0) {
  return __ctxOut({
    skip_materiales: true,
    motivo: 'Sin materiales (solo venían horas presupuestadas / estimación, que NO se registran como consumo)',
    timesheet_line_id: timesheetLineId,
    debug: {
      input_pv_len: Array.isArray($json.productos_validados) ? $json.productos_validados.length : null,
      valid_pv_len: Array.isArray(valid.productos_validados) ? valid.productos_validados.length : null,
      input_prod_len: Array.isArray($json.productos) ? $json.productos.length : null,
      input_dp_prod_len: Array.isArray($json.datos_parte?.productos) ? $json.datos_parte.productos.length : null,
      seed_prod_len: Array.isArray(seedParte.productos) ? seedParte.productos.length : null,
      dp_seed_prod_len: Array.isArray(dpObj?.datos_parte?.productos) ? dpObj.datos_parte.productos.length : null,
      reg_len: Array.isArray(reg.productos) ? reg.productos.length : null,
      norm_len: Array.isArray(norm.productos) ? norm.productos.length : null,
      horas_presupuestadas: reg.horas_presupuestadas ?? $json.horas_presupuestadas ?? null,
      reg_wrap_has_registro: !!regNodeWrap?.registro,
      reg_wrap_keys: regNodeWrap ? Object.keys(regNodeWrap) : null,
    },
  });
}

// ✅ 4) separar conId vs sinId
const conId = [];
const sinId = [];

for (const p of productos) {
  const name = String(p.product_name || p.nombre || p.notes || '').trim();
  const qty = Number(p.quantity || p.cantidad || 1);

  let pid = p.product_id;
  if (Array.isArray(pid)) pid = pid[0];
  if (pid === false || pid === null || pid === undefined || pid === '') pid = null;
  else pid = Number(pid);

  const uom =
    (Array.isArray(p.uom_id) ? p.uom_id[0] : p.uom_id) ||
    (Array.isArray(p.product_uom_id) ? p.product_uom_id[0] : p.product_uom_id) ||
    null;

  const item = {
    timesheet_line_id: timesheetLineId,
    product_id: pid,
    quantity: Number.isFinite(qty) && qty > 0 ? qty : 1,
    notes: name,
  };

  if (uom) item.product_uom_id = Number(uom);

  if (Number.isFinite(pid) && pid > 0) conId.push(item);
  else if (name) sinId.push({ nombre: name, cantidad: item.quantity });
}

if (conId.length === 0 && sinId.length === 0) {
  return __ctxOut({
    skip_materiales: true,
    motivo: 'Materiales vacíos o sin nombre (tras filtrar horas presupuestadas)',
    timesheet_line_id: timesheetLineId,
  });
}

// ✅ 5) db/uid
const db =
  reg.db ||
  norm.db ||
  valid.db ||
  $json.db ||
  seed.db ||
  'lsanchezgoshawk-botpartesdetrabajo-main-32341811';

const uid =
  reg.uid ||
  norm.uid ||
  valid.uid ||
  $json.uid ||
  seed.uid ||
  auth.result ||
  2;

const pass = 'admin';

// ✅ 6) si faltan IDs -> pedir resolución por búsqueda
if (sinId.length > 0 && conId.length === 0) {
  const names = sinId.map((x) => x.nombre).filter(Boolean);

  let domain = [];
  if (names.length === 1) {
    domain = [['name', 'ilike', names[0]]];
  } else {
    for (let i = 0; i < names.length; i++) {
      if (i < names.length - 1) domain.push('|');
      domain.push(['name', 'ilike', names[i]]);
    }
  }

  const payloadBuscarProductos = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        db, Number(uid), pass,
        'product.product', 'search_read',
        [domain],
        { fields: ['id', 'name', 'display_name', 'uom_id', 'default_code'], limit: 80 },
      ],
    },
    id: Math.floor(Math.random() * 1e6),
  };

  return __ctxOut({
    skip_materiales: true,
    motivo: 'Hay materiales pero sin product_id. Hay que resolverlos por nombre antes de registrar consumo.',
    timesheet_line_id: timesheetLineId,
    productos_sin_id: sinId,
    necesita_resolver_productos: true,
    payload_buscar_productos: payloadBuscarProductos,
    db,
    uid: Number(uid),
  });
}

// ✅ 7) si hay IDs -> crear líneas de consumo en el parte (account.analytic.line.product)
if (conId.length > 0) {
  const payloadCreate = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        db,
        Number(uid),
        pass,
        'account.analytic.line.product',
        'create',
        [conId],
      ],
    },
    id: Math.floor(Math.random() * 1e6),
  };

  return __ctxOut({
    skip_materiales: false,
    payload: payloadCreate,
    timesheet_line_id: timesheetLineId,
    productos_creados: conId.length,
    productos_sin_id: sinId,
    db,
    uid: Number(uid),
  });
}

// fallback final
return __ctxOut({
  skip_materiales: true,
  motivo: 'No hay materiales registrables',
  timesheet_line_id: timesheetLineId,
  debug_paths: {
    input_productos_validados: Array.isArray($json.productos_validados) ? $json.productos_validados.length : null,
    valid_productos_validados: Array.isArray(valid.productos_validados) ? valid.productos_validados.length : null,
    input_productos: Array.isArray($json.productos) ? $json.productos.length : null,
    input_datos_parte_productos: Array.isArray($json.datos_parte?.productos) ? $json.datos_parte.productos.length : null,
    seed_productos: Array.isArray(seedParte.productos) ? seedParte.productos.length : null,
    dp_productos: Array.isArray(dpObj?.datos_parte?.productos) ? dpObj.datos_parte.productos.length : null,
    reg_len: Array.isArray(reg.productos) ? reg.productos.length : null,
    norm_len: Array.isArray(norm.productos) ? norm.productos.length : null,
  },
});

// ✅ Registrar Horas Directo FSM
// ✅ FIXES:
// 1) Idempotencia: si ya existe timesheet_line_id (input o memoria), NO vuelve a crear horas
// 2) Transcripción: MENSAJE INICIAL siempre el inicial; MENSAJE HORAS solo si texto tiene número válido
// 3) Evita que "sí" o "juntas" contaminen los mensajes
// 4) En corrección de productos, reutiliza transcripción guardada en memoria (no recalcula)

const safeNodeJson = (name) => {
  try { return $items(name, 0)?.[0]?.json ?? null; } catch { return null; }
};

const parseJSONSafe = (v) => {
  try { return typeof v === 'string' ? JSON.parse(v) : (v || {}); } catch { return {}; }
};

const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const clean = (s) => String(s ?? '').trim();

const x = $json || {};

// -------------------------
// ✅ Contexto base
// -------------------------
const seed = safeNodeJson('Registrar Tarea Odoo') || {};
const seedReg = seed.datos_registrados || {};

const memRow = safeNodeJson('Preparar Datos AI Agent') || {};
const pendientes = parseJSONSafe(memRow?.datos_pendientes);

const normalizado = safeNodeJson('Normalizar Parte+Materiales FSM') || {};
const authNode = safeNodeJson('Autenticar Odoo') || {};
const prepCompleto = safeNodeJson('FSM ▸ Preparar Datos Completos') || {};
const prepUser = safeNodeJson('Preparar Buscar Usuario Odoo') || {};

// -------------------------
// ✅ Flags de rama
// -------------------------
const enCorreccionProductos =
  memRow?.esperando_confirmacion === 'correccion_productos' ||
  x.necesita_resolver_productos === true ||
  (Array.isArray(x.productos_sin_id) && x.productos_sin_id.length > 0) ||
  !!x.payload_buscar_productos;

// -------------------------
// ✅ Idempotencia: detectar si YA existe línea creada
// -------------------------
const existingTimesheetLineId = toNum(
  x.timesheet_line_id ||
  x.timesheetLineId ||
  x.timesheet_line_id_creado ||
  pendientes.timesheet_line_id ||
  pendientes.timesheetLineId
);

// ⚠️ Si ya hay timesheet_line_id, NO volvemos a crear horas
if (existingTimesheetLineId && existingTimesheetLineId > 0) {
  return {
    payload: null,
    skip_registrar_horas: true,
    motivo: enCorreccionProductos
      ? 'Reentrada por corrección de productos: NO se vuelven a registrar horas'
      : 'Ya existía timesheet_line_id: NO se vuelven a registrar horas',
    timesheet_line_id: existingTimesheetLineId,
    ...x,
    registro: {
      ...(x.registro || {}),
      chat_id: x.chat_id || pendientes.chat_id || memRow.chat_id || seed.chat_id || normalizado.chat_id,
      db: x.db || pendientes.db || seed.db || normalizado.db || 'lsanchezgoshawk-botpartesdetrabajo-main-32341811',
      uid: toNum(x.uid || pendientes.uid || seed.uid || normalizado.uid || authNode?.result) || 2,
      timesheet_line_id: existingTimesheetLineId,
    },
  };
}

// -------------------------
// ✅ IDs tarea/proyecto
// -------------------------
const tareaId = toNum(
  x.tarea_id ||
  x.task_id ||
  x.datos_registrados?.task_id ||
  pendientes.tarea_id ||
  seedReg.task_id
);

const proyectoId = toNum(
  x.proyecto_id ||
  x.project_id ||
  x.datos_registrados?.project_id ||
  pendientes.proyecto_id ||
  seedReg.project_id
);

const tareaNombre =
  x.tarea ||
  x.tarea_nombre ||
  pendientes.tarea_nombre ||
  seed.tarea ||
  'Tarea';

const proyectoNombre =
  x.proyecto_nombre ||
  pendientes.proyecto_nombre ||
  seed.proyecto_nombre ||
  'Proyecto';

const datosParte =
  x.datos_parte ||
  pendientes.datos_parte ||
  seed.datos_parte ||
  {};

// -------------------------
// ✅ descripcion y productos
// -------------------------
const descripcion =
  x.descripcion ||
  x.datos_parte?.descripcion ||
  datosParte?.descripcion ||
  pendientes?.datos_parte?.descripcion ||
  seedReg?.name ||
  '';

const productos =
  x.productos ||
  x.datos_parte?.productos ||
  datosParte?.productos ||
  pendientes?.datos_parte?.productos ||
  [];

// -------------------------
// ✅ HORAS (solo crear si hay >0)
// -------------------------
let horas = null;
const horasCandidatos = [
  x.horas,
  x.unit_amount,
  x.datos_registrados?.unit_amount,
  x.datos_parte?.horas,
  datosParte.horas,
  pendientes.datos_parte?.horas,
  seedReg.unit_amount,
];

for (const candidate of horasCandidatos) {
  const num = toNum(candidate);
  if (num !== null && num > 0) {
    horas = num;
    break;
  }
}

horas = horas ?? 0;

if (horas <= 0) {
  const debugInfo = {
    'x.horas': x.horas,
    'x.unit_amount': x.unit_amount,
    'x.datos_registrados?.unit_amount': x.datos_registrados?.unit_amount,
    'x.datos_parte?.horas': x.datos_parte?.horas,
    'datosParte.horas': datosParte.horas,
    'pendientes.datos_parte?.horas': pendientes.datos_parte?.horas,
    'seedReg.unit_amount': seedReg.unit_amount,
    'horas_final': horas,
  };
  throw new Error(`Horas inválidas: ${horas}. DEBUG: ${JSON.stringify(debugInfo, null, 2)}`);
}

// -------------------------
// ✅ Credenciales
// -------------------------
const DB =
  x.db ||
  pendientes.db ||
  seed.db ||
  normalizado.db ||
  'lsanchezgoshawk-botpartesdetrabajo-main-32341811';

const UID =
  toNum(x.uid_admin || x.uid || pendientes.uid_admin || seed.uid || normalizado.uid) ||
  toNum(authNode?.result) ||
  2;

const PASS =
  x.pass_admin ||
  x.pass ||
  pendientes.pass_admin ||
  'admin';

const hoy = new Date().toISOString().split('T')[0];

// -------------------------
// ✅ user_id desde "Buscar Usuario Odoo"
// -------------------------
let userIdFromPerfil = null;
let userNameFromPerfil = null;
let usuario = null;

try {
  const listaUsuarios =
    x?.result ??
    x?.body?.result ??
    x?.data?.result ??
    x?.json?.result ??
    [];

  usuario = Array.isArray(listaUsuarios) && listaUsuarios.length ? listaUsuarios[0] : null;
  userIdFromPerfil = usuario?.id ?? null;
  userNameFromPerfil = usuario?.name ?? null;
} catch {}

/** Primer empleado vinculado al usuario (res.users.employee_ids). */
let employeeIdResolved = null;
try {
  const eids = usuario?.employee_ids;
  if (Array.isArray(eids) && eids.length) {
    const e0 = eids[0];
    const n = Array.isArray(e0) ? Number(e0[0]) : Number(e0);
    if (Number.isFinite(n) && n > 0) employeeIdResolved = n;
  }
} catch {}

// -------------------------
// ✅ Diagnóstico
// -------------------------
const esDiagnosis =
  x.is_diagnosis_task === true ||
  datosParte.is_diagnosis_task === true ||
  pendientes.is_diagnosis_task === true ||
  false;

// -------------------------
// ✅ TRANSCRIPCIÓN (NO contaminada + no recalcular en corrección)
// -------------------------
let transcripcionCompleta = '';

if (enCorreccionProductos) {
  // ✅ En corrección: usa lo guardado (no lo machaques con "juntas"/"si")
  transcripcionCompleta =
    clean(pendientes?.transcripcion_real) ||
    clean(pendientes?.transcripcion_original) ||
    clean(descripcion) ||
    'Sin transcripción disponible';
} else {
  // ✅ MENSAJE INICIAL: SOLO de fuentes iniciales estables
  const primerMensaje =
    datosParte?.mensaje_usuario_original ||
    datosParte?.transcripcion_original ||
    pendientes?.datos_parte?.mensaje_usuario_original ||
    pendientes?.datos_parte?.transcripcion_original ||
    seed?.mensaje_usuario_original ||
    seed?.transcripcion_original ||
    seed?.datos_parte?.mensaje_usuario_original ||
    seed?.datos_parte?.transcripcion_original ||
    null;

  const memModoEsperando =
    clean(memRow.esperando_confirmacion || pendientes?.modo || '');

  const mensajeActualRaw =
    memRow?.mensaje_usuario ||
    x.mensaje_usuario ||
    prepCompleto?.message?.text ||
    prepUser?.message?.text ||
    normalizado?.message?.text ||
    x.message?.text ||
    x.body?.message?.text ||
    x.text ||
    null;

  const parseHorasFromText = (txt, opts = {}) => {
    const trimmedMsg = clean(txt).toLowerCase();
    if (!trimmedMsg) return null;

    const banal = new Set(['si', 'sí', 'ok', 'vale', 'de acuerdo', 'correcto']);
    if (banal.has(trimmedMsg)) return null;

    // Si el usuario elige una tarea de una lista («1», «2»…), ese entero corto NO son horas aquí.
    const soloEnterosCortos = /^[0-9]{1,3}$/.test(trimmedMsg.replace(/\s+/g, ''));
    const memModo = opts.memEsperando || '';
    const inicial = clean(opts.inicialMensaje || '');
    const eligiendoListaTarea =
      memModo === 'elegir_tarea_multiple' ||
      memModo === 'confirmar_tarea_unica' ||
      memModo === 'elegir_tarea_multiple_imagen_previa' ||
      /** fallback: mensaje inicial largo + sólo dígitos ahora ⇒ casi siempre elección numerada */
      (inicial.length >= 48 && soloEnterosCortos);

    if (soloEnterosCortos && eligiendoListaTarea) {
      return null;
    }

    const m = trimmedMsg.replace(',', '.').match(/(\d+(\.\d+)?)/);
    if (!m) return null;

    const n = Number(m[1]);
    return Number.isFinite(n) && n > 0 ? n : null;
  };

  const p = clean(primerMensaje);
  const inicialParaParse =
    primerMensaje ||
    pendientes?.datos_parte?.mensaje_usuario_original ||
    pendientes?.datos_parte?.transcripcion_original ||
    seed?.mensaje_usuario_original ||
    seed?.transcripcion_original ||
    '';

  const horasEnTexto = parseHorasFromText(mensajeActualRaw, {
    memEsperando: memModoEsperando,
    inicialMensaje: inicialParaParse,
  });

  const trimmedActualDigits = clean(mensajeActualRaw).replace(/\s+/g, '');
  const soloDigMsgActual = /^[0-9]{1,3}$/.test(trimmedActualDigits);
  const horasEnDatosParte = toNum(datosParte.horas ?? pendientes.datos_parte?.horas);

  let mensajeHoras = horasEnTexto !== null ? clean(mensajeActualRaw) : null;

  /**
   * Tras elegir tarea con «1», el mensaje actual no debe interpretarse como «1 hora» si ya había
   * horas en datos_parte (p.ej. 5h en el mensaje inicial).
   */
  if (
    mensajeHoras &&
    soloDigMsgActual &&
    horasEnDatosParte != null &&
    horasEnDatosParte > 0 &&
    horasEnTexto !== null &&
    horasEnTexto !== horasEnDatosParte
  ) {
    mensajeHoras = null;
  }

  if (p && mensajeHoras) {
    transcripcionCompleta = (p === mensajeHoras)
      ? p
      : `🟦 MENSAJE INICIAL:\n${p}\n\n🟩 MENSAJE HORAS:\n${mensajeHoras}`;
  } else if (p) {
    transcripcionCompleta = p; // ✅ si no hay mensaje horas válido, solo inicial
  } else if (mensajeHoras) {
    transcripcionCompleta = mensajeHoras;
  } else {
    transcripcionCompleta = clean(descripcion) || 'Sin transcripción disponible';
  }
}

const transcripcionReal = transcripcionCompleta;

// -------------------------
// ✅ Horas presupuestadas
// -------------------------
const horasPresupuestadas =
  toNum(
    x.horas_presupuestadas ||
    datosParte.horas_presupuestadas ||
    pendientes.horas_presupuestadas ||
    seed.horas_presupuestadas ||
    normalizado?.horas_presupuestadas ||
    0
  ) ?? 0;

// -------------------------

// -------------------------
// ✅ Travel fields (distancia y tiempo de desplazamiento)
// -------------------------
const travel_distance_km = toNum(
  x.travel_distance_km ||
  datosParte.travel_distance_km ||
  pendientes?.datos_parte?.travel_distance_km ||
  pendientes?.travel_distance_km ||
  seed.travel_distance_km ||
  normalizado?.travel_distance_km ||
  0
) ?? 0;

const travel_time_hours = toNum(
  x.travel_time_hours ||
  datosParte.travel_time_hours ||
  pendientes?.datos_parte?.travel_time_hours ||
  pendientes?.travel_time_hours ||
  seed.travel_time_hours ||
  normalizado?.travel_time_hours ||
  0
) ?? 0;

console.log('🚗 Travel distance_km:', travel_distance_km);
console.log('⏱️ Travel time_hours:', travel_time_hours);

// ✅ Descripción mejorada
// -------------------------
let descripcionMejorada = (descripcion || seedReg.name || `Parte - ${tareaNombre}`).trim();

if (esDiagnosis && horasPresupuestadas > 0) {
  descripcionMejorada = `${descripcionMejorada} [PRESUPUESTO: ${horasPresupuestadas}h]`;
}

if (Array.isArray(productos) && productos.length > 0) {
  const listaProductos = productos
    .map(p => `- ${p.nombre || p.product_name || 'Producto sin nombre'}: ${p.cantidad || p.quantity || 1} unidad(es)`)
    .join('\n');

  if (esDiagnosis) {
    descripcionMejorada = `${descripcionMejorada}\n\n📋 PRODUCTOS MENCIONADOS (Presupuesto):\n${listaProductos}`;
  } else {
    descripcionMejorada = `${descripcionMejorada}\n\n📦 MATERIALES UTILIZADOS:\n${listaProductos}`;
  }
}

if (transcripcionCompleta) {
  descripcionMejorada = `${descripcionMejorada}\n\n🗒️ CONTEXTO COMPLETO (OPERARIO):\n${transcripcionCompleta}`;
}

// -------------------------
// ✅ Validación IDs
// -------------------------
if (!tareaId || !proyectoId) {
  throw new Error(
    `Faltan IDs. task_id=${tareaId} project_id=${proyectoId}. ` +
    `Revisa que lleguen desde Registrar Tarea Odoo / pendientes / input.`
  );
}

// -------------------------
// ✅ Payload create (account.analytic.line) + employee_id (hr_timesheet)
// -------------------------
const urlJsonRpc = 'https://lsanchezgoshawk-botpartesdetrabajo.odoo.com/jsonrpc';

const httpRpc = async (body) =>
  this.helpers.httpRequest({
    method: 'POST',
    url: urlJsonRpc,
    body,
    json: true,
  });

const buildSalida = async () => {
  let employeeId = employeeIdResolved;

  if (!employeeId && userIdFromPerfil) {
    try {
      const rr = await httpRpc({
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'object',
          method: 'execute_kw',
          args: [
            DB,
            UID,
            PASS,
            'hr.employee',
            'search_read',
            [[['user_id', '=', Number(userIdFromPerfil)], ['active', '=', true]]],
            { fields: ['id', 'name'], limit: 5 },
          ],
        },
        id: Math.floor(Math.random() * 1e6),
      });
      const rows = Array.isArray(rr?.result) ? rr.result : [];
      if (rows.length) employeeId = rows[0].id;
    } catch (e) {
      console.log('⚠️ hr.employee search_read:', e?.message || e);
    }
  }

  if (!employeeId) {
    throw new Error(
      '❌ Falta **empleado (hr.employee) activo** vinculado a tu usuario Odoo para registrar el parte. ' +
        'Solución típica: en RR.HH crea/actívalo el empleado y enlázalo desde la **ficha Usuario** (relación usuarios-empleados), ' +
        'asignándole la **compañía** correcta del proyecto.',
    );
  }

  const valoresParte = {
    name: descripcionMejorada,
    project_id: proyectoId,
    task_id: tareaId,
    unit_amount: horas,
    date: hoy,
    transcripcion_real: transcripcionReal,
    is_diagnosis_task: esDiagnosis,
    travel_distance_km: travel_distance_km,
    travel_time_hours: travel_time_hours,
    employee_id: employeeId,
    ...(userIdFromPerfil ? { user_id: Number(userIdFromPerfil) } : {}),
  };

  const payload = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        DB,
        UID,
        PASS,
        'account.analytic.line',
        'create',
        [[valoresParte]],
      ],
    },
    id: Math.floor(Math.random() * 1e6),
  };

  return {
    payload,
    skip_registrar_horas: false,
    registro: {
      chat_id: x.chat_id || seed.chat_id || normalizado.chat_id || memRow?.chat_id,
      proyecto: proyectoNombre,
      tarea: tareaNombre,
      horas,
      horas_presupuestadas: horasPresupuestadas,
      is_diagnosis_task: esDiagnosis,
      descripcion: (descripcion || seedReg.name || `Parte - ${tareaNombre}`).trim(),
      transcripcion_original: transcripcionCompleta,
      transcripcion_real: transcripcionReal,
      task_id: tareaId,
      project_id: proyectoId,
      travel_distance_km: travel_distance_km,
      travel_time_hours: travel_time_hours,
      odoo_user: x.odoo_user || pendientes.odoo_user || seed.odoo_user || normalizado.odoo_user || memRow?.odoo_user || null,
      odoo_user_id: userIdFromPerfil || null,
      odoo_user_name: userNameFromPerfil || null,
      employee_id: employeeId,
      productos,
      db: DB,
      uid: UID,
    },
  };
};

return await buildSalida();

// ✅ Preparar Buscar Usuario Odoo (robusto para rama registrar_tarea)

const x = $json;

// helper: leer json de otro nodo si existe / se ejecutó
const safeNodeJson = (name) => {
  try {
    const it = $items(name, 0);
    return it?.[0]?.json ?? null;
  } catch {
    return null;
  }
};

// 1) Fuentes posibles
const normalizado = safeNodeJson('Normalizar Parte+Materiales FSM') || null;
const authNode = safeNodeJson('Autenticar Odoo') || null;

const memRow = safeNodeJson('Preparar Datos AI Agent') || null;

// 2) Parse seguro de datos_pendientes de Postgres
const parseJSONSafe = (v) => {
  try { return typeof v === 'string' ? JSON.parse(v) : (v || {}); }
  catch { return {}; }
};

const pendientes = parseJSONSafe(memRow?.datos_pendientes);

// 3) Credenciales / contexto (prioridad: input -> pendientes -> normalizado -> defaults)
const DB =
  x.db ||
  pendientes.db ||
  normalizado?.db ||
  'lsanchezgoshawk-botpartesdetrabajo-main-32341811';

let UID =
  x.uid_admin ||
  x.uid ||
  pendientes.uid_admin ||
  normalizado?.uid ||
  2;

// si existe Autenticar Odoo y trae result, úsalo
if (authNode?.result) UID = authNode.result;

const PASS =
  x.pass_admin ||
  pendientes.pass_admin ||
  'admin';

// 4) Email del usuario final (muy importante)
const email =
  x.odoo_user ||
  pendientes.odoo_user ||
  normalizado?.odoo_user ||
  memRow?.odoo_user ||
  '';

// Si no hay email, NO rompas el flujo: devuelve skip para que lo bypasses
if (!email) {
  return {
    ...x,
    db: DB,
    uid: UID,
    pass_admin: PASS,
    skip_user_lookup: true,
    motivo: 'Falta odoo_user/email para buscar res.users',
  };
}

// 5) Payload JSON-RPC
const payload = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      DB, UID, PASS,
      'res.users', 'search_read',
      [[
        '|',
        ['login', '=', email],
        ['email', '=', email],
      ]],
      { fields: ['id', 'name', 'login', 'email', 'partner_id', 'employee_ids'], limit: 1 },
    ],
  },
  id: Math.floor(Math.random() * 1e6),
};

return {
  ...x,
  db: DB,
  uid: UID,
  pass_admin: PASS,
  odoo_user: email,
  payload,
};

// Log para datos inválidos que no se pueden guardar en PostgreSQL
console.log('❌ DATOS INVÁLIDOS - No se guardó en PostgreSQL:');
console.log('📄 Datos recibidos:', JSON.stringify($json, null, 2));
console.log('🚫 Razón:', $json.razon || 'No especificada');
console.log('📊 Chat ID original:', $json.chat_id_original);
console.log('🔢 Chat ID numérico:', $json.chat_id_numerico);

return { 
  mensaje: 'Datos no guardados en PostgreSQL por ser inválidos',
  detalles: $json 
};

