  if (!tid) continue;
  const v = (g['unit_amount'] ?? g['unit_amount:sum'] ?? 0);
  hoursByTask[tid] = Number(v) || 0;
}

// KPI globales
let plan = 0, eff = 0;
for (const t of tasks) {
  if (typeof t.planned_hours === 'number') plan += Number(t.planned_hours || 0);
  eff += Number(hoursByTask[t.id] || t.effective_hours || 0);
}
const avance = plan > 0 ? Math.min(100, Math.max(0, Math.round((eff/plan)*100))) : null;

// Barra de progreso (10 bloques)
const progressBar = (pct) => {
  const total = 10;
  const filled = Math.round((pct/100)*total);
  return '▰'.repeat(filled) + '▱'.repeat(total - filled);
};

// Icono por etapa / estado + retraso
const stageIcon = (stageName, isLate) => {
  const s = String(stageName || '').toLowerCase();
  const base = s.includes('done') || s.includes('hecho') ? '✅'
             : s.includes('progress') || s.includes('en ') ? '🚧'
             : '🆕';
  return isLate ? '⏰' : base;
};

// Cabecera
let texto = `🗂️ *Proyecto:* \`${clean(project?.name || '—')}\`\n`;
texto += `👤 *Cliente:* \`${clean(project?.partner_id ? project.partner_id[1] : '—')}\`  •  👨‍💼 *PM:* \`${clean(project?.user_id ? project.user_id[1] : '—')}\`\n`;
