const asStr = (v) => (v == null ? '' : String(v).trim());

const normalizar = (s) =>
  String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '') // quita acentos
    .trim();

// Convierte HTML a texto plano con viñetas
const productosAPlano = (html) => {
  if (!html) return '• No especificados';

  const txt = String(html)
    .replace(/<\/li>\s*<li[^>]*>/gi, '\n• ')
    .replace(/<li[^>]*>/gi, '• ')
    .replace(/<\/li>/gi, '')
    .replace(/<\/?(ul|ol)[^>]*>/gi, '')
    .replace(/<\/?(strong|b|em|i|u|ins|s|strike|del|p|div|span|h1|h2|h3|h4|h5)[^>]*>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  return txt ? txt : '• No especificados';
};

// Extrae "Cliente: X" del HTML de description
const extraerClienteDeDescripcion = (html) => {
  const m = String(html || '').match(/<strong>\s*Cliente:\s*<\/strong>\s*([^<]+)/i);
  return m ? m[1].trim() : '';
};

// Extrae el <ul> de "Productos/Servicios Solicitados" y lo convierte a texto plano
const extraerProductosDeDescripcion = (html) => {
  const m = String(html || '').match(/Productos\/Servicios Solicitados<\/h3>\s*(<ul[\s\S]*?<\/ul>)/i);
  return m ? productosAPlano(m[1]) : '• No especificados';
};

