 */
function mencionaUsoConsumoMaterialEnTexto(raw) {
  const t = normalizar(raw);
  if (!t) return false;
  if (
    /\b(he|hemos|has|han)\s*(utilizado|utilizamos|utilizaron|consumido|consumida|consumidos|consumidas)\b/.test(
      t,
    )
  )
    return true;
  if (/\b(he|hemos|has|han)\s+uso\s+/.test(t)) return true;
  if (/\b(he|hemos|has|han)\s*(usan|consumen|consumimos|consumis|consumieron)\b/.test(t))
    return true;
  if (/\bus(e|emos|imos|amos|aron)\s+/.test(t)) return true;
  if (/\b(me|nos)\s+llev(o|amos|aron)\b/.test(t)) return true;
  return false;
}

