}

// Devolver datos originales + imagen en base64
return {
  ...datosOriginales,
  imagen_base64: archivoBase64,
  imagen_descargada: !!archivoBase64
};

// ✅ PREPARAR ADJUNTO DIRECTO (PARTE) DESDE DESCARGA HTTP (rama ...1)
const safeItems = (nodeName) => {
  try {
    return $items(nodeName, 0, 0) || [];
  } catch (e) {
    return [];
  }
};

const firstJson = (nodeName) => {
  const it = safeItems(nodeName);
  return it[0]?.json || {};
};

const datosAnteriores = firstJson('Construir URL Descarga Parte1');
const ultimo = firstJson('Consultar Último Parte Odoo1');

const horasId = Number(ultimo.ultimo_horas_id || datosAnteriores.horas_id || 0);
const chatId = datosAnteriores.chat_id ?? ultimo.chat_id ?? null;

if (!Number.isFinite(horasId) || horasId <= 0) {
  return {
    ...datosAnteriores,
    chat_id: chatId,
    imagen_lista_para_subir: false,
    imagen_adjuntada: false,
    error: 'ultimo_horas_id inválido para adjuntar.'
  };
}

// 1) Binario del item actual
let bin = null;
const binKeys = Object.keys($binary || {});
if (binKeys.length) bin = $binary[binKeys[0]];

// 2) Fallback: binario desde "Descargar Imagen REAL (PARTE)1"
if (!bin || !bin.data) {
  const httpItems = safeItems('Descargar Imagen REAL (PARTE)1');
  if (httpItems.length && httpItems[0].binary) {
    const httpBinKeys = Object.keys(httpItems[0].binary);
    if (httpBinKeys.length) bin = httpItems[0].binary[httpBinKeys[0]];
  }
}

// 3) Fallback: binario desde "Download media"
if (!bin || !bin.data) {
  const waItems = safeItems('Download media');
  if (waItems.length && waItems[0].binary) {
    const waBinKeys = Object.keys(waItems[0].binary);
    if (waBinKeys.length) bin = waItems[0].binary[waBinKeys[0]];
  }
}

if (!bin || !bin.data) {
  return {
    ...datosAnteriores,
    chat_id: chatId,
    imagen_lista_para_subir: false,
    imagen_adjuntada: false,
    error: 'No se encontraron datos binarios del archivo descargado'
  };
}

// base64 -> buffer
const archivoBinario = Buffer.from(bin.data, 'base64');

// detectar firma
const sig = archivoBinario.slice(0, 8).toString('hex').toUpperCase();
let mimetype = 'image/jpeg';
let extension = 'jpg';

if (sig.startsWith('89504E47')) { mimetype = 'image/png'; extension = 'png'; }
else if (sig.startsWith('FFD8FF')) { mimetype = 'image/jpeg'; extension = 'jpg'; }
else if (sig.startsWith('47494638')) { mimetype = 'image/gif'; extension = 'gif'; }
else if (sig.startsWith('52494646')) { mimetype = 'image/webp'; extension = 'webp'; }

const archivoBase64 = archivoBinario.toString('base64');
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const nombreArchivo = `Parte-${horasId}-${ts}.${extension}`;

const db = 'lsanchezgoshawk-botpartesdetrabajo-main-32341811';
const uid = 2;
const pass = 'admin';

const attachmentVals = {
  name: nombreArchivo,
  datas: archivoBase64,
  res_model: 'account.analytic.line',
  res_id: horasId,
  timesheet_line_id: horasId,
  mimetype,
  type: 'binary',
  is_repair_photo: true,
  photo_type: 'none',
};

const consultaAdjunto = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [db, uid, pass, 'ir.attachment', 'create', [attachmentVals], { context: { force_google_drive: true } }],
  },
  id: Math.floor(Math.random() * 1000000),
};

return {
  ...datosAnteriores,
  chat_id: chatId,
  horas_id: horasId,
  odoo_api_payload: {
    chat_id: chatId,
    horas_id: horasId,
    filename: nombreArchivo,
    mimetype,
    image_base64: archivoBase64,
  },
  consulta_adjunto: consultaAdjunto,
  imagen_lista_para_subir: true,
  imagen_adjuntada: true,
  archivo_info: {
    nombre: nombreArchivo,
    mimetype,
    tamaño: archivoBinario.length,
  }
};

const itemActual = $json;

// UID robusto
const auth = $('Autenticar Odoo para Resumen').all();
let uid = null;
for (const it of auth) {
  if (it.json?.result) { uid = it.json.result; break; }
}
if (!uid) throw new Error('❌ UID no disponible');

// Fecha HOY en Madrid (siempre)
const fechaHoy = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/Madrid' });
const inicioDia = `${fechaHoy} 00:00:00`;
const finDia = `${fechaHoy} 23:59:59`;

// Resultado de res.users (lo trae el HTTP Buscar Usuario Odoo)
const userRes = Array.isArray(itemActual.result) ? itemActual.result : [];
const userOdoo = userRes[0];

if (!userOdoo?.id) {
  return {
    json: {
      ...itemActual,
      uid,
      fechaHoy,
      inicioDia,
      finDia,
      consulta_fsm: null,
      fsm_hoy: [],
      mensaje_eventos: `🛠️ **TU PLANIFICACIÓN DEL DÍA**\n⚠️ No se encontró el usuario Odoo para: ${itemActual.odoo_user}\n`
    }
  };
}

const userIdOdoo = userOdoo.id;

// ✅ Dominio SOLAPE (overlap) para incluir:
// - tareas dentro del día
// - tareas todo el día
// - tareas multi-día que "tocan" hoy
const dominioFSM = [
  ["planned_date_begin", "<=", finDia],
  ["date_deadline", ">=", inicioDia],
  ["user_ids", "in", [userIdOdoo]],
  ["state", "not in", ["1_done", "1_canceled"]],
  ["fsm_done", "!=", true]
];

// (Opcional) Si en tu Odoo algunas tareas tienen planned_date_begin vacío,
// puedes OR para permitirlas usando date_deadline. Te lo dejo preparado abajo.
// Si quieres activarlo, dímelo y lo ajusto, porque depende de cómo planifica FSM.

const consultaFSM = {
  jsonrpc: "2.0",
  method: "call",
  params: {
    service: "object",
    method: "execute_kw",
    args: [
      "lsanchezgoshawk-botpartesdetrabajo-main-32341811",
      uid,
      "admin",
      "project.task",
      "search_read",
      [dominioFSM],
      {
        fields: [
          "name",
          "planned_date_begin",
          "date_deadline",
          "partner_id",
          "project_id",
          "stage_id",
          "user_ids",
          "fsm_done"
        ],
        order: "planned_date_begin asc"
      }
    ]
  },
  id: Math.floor(Math.random() * 1000000)
};

return {
  json: {
    ...itemActual,
    uid,
    fechaHoy,
    inicioDia,
    finDia,
    consulta_fsm: consultaFSM,
    odoo_user_name: userOdoo.name
  }
};

