// Memoria: preguntar si marcar tarea hecha tras parte OK
const safeFirstJson = (nodeName) => {
  try {
    const h = $(nodeName);
    if (h && typeof h.first === 'function') {
      const f = h.first();
      if (f?.json) return f.json;
    }
  } catch (_) {}
  try {
    const arr = $items(nodeName, 0);
    return arr && arr[0] ? arr[0].json : null;
  } catch (_) {
    return null;
  }
};

function toNumPos(v) {
  const n = Number(v);
  return Number.isFinite(n) && n > 0 ? n : null;
}

function horasIdDesdeRegistro(reg, httpHoras) {
  let horasId =
    httpHoras?.result ?? httpHoras?.body?.result ?? httpHoras?.json?.result ?? null;
  if (Array.isArray(horasId)) horasId = horasId[0];
  horasId = horasId != null ? Number(horasId) : null;
  if (Number.isFinite(horasId) && horasId > 0) return horasId;
  const alt = Number(reg.timesheet_line_id);
  return Number.isFinite(alt) && alt > 0 ? alt : null;
}

function fuenteResumenParaMarcarHecha() {
  try {
    const rep = $('Reapilar tras Guardar último Horas ID').first()?.json;
    const tid = Number(rep?.resumen_creado?.tarea_id);
    const chatOk = rep?.chat_id !== undefined && rep?.chat_id !== null && String(rep.chat_id).trim() !== '';
    if (chatOk && Number.isFinite(tid) && tid > 0) return rep;
  } catch (_) {}

  try {
    const lst = $('Limpiar & Resumen').all();
    let best = null;
    let bestTid = 0;
    for (const it of lst) {
      const j = it?.json || {};
      const tid = Number(j?.resumen_creado?.tarea_id);
      if (!(Number.isFinite(tid) && tid > 0)) continue;
      const chatOk = j.chat_id !== undefined && j.chat_id !== null && String(j.chat_id).trim() !== '';
      if (!chatOk) continue;
      if (tid >= bestTid) {
        bestTid = tid;
        best = j;
      }
    }
    if (best) return best;
  } catch (_) {}

  try {
    const lim = $('Limpiar & Resumen').first()?.json || {};
    const tid = Number(lim?.resumen_creado?.tarea_id);
    if (lim.chat_id && Number.isFinite(tid) && tid > 0) return lim;
  } catch (_) {}

  // Rama «Confirmar Todo» / entregas: sin Limpiar & Resumen, usar registro de horas
  const regWrap = safeFirstJson('Registrar Horas Directo FSM') || {};
  const reg = regWrap.registro || regWrap || {};
  const httpHoras = safeFirstJson('HTTP Registrar Horas Directo FSM') || {};
  const seed = safeFirstJson('Registrar Tarea Odoo') || {};
  const extraer = safeFirstJson('Extraer partner_id') || {};

  const tid =
    toNumPos(reg.task_id) ??
    toNumPos(reg.tarea_id) ??
    toNumPos(seed.tarea_id) ??
    toNumPos(seed.datos_registrados?.task_id) ??
    toNumPos(extraer.task_id) ??
    toNumPos(extraer.result?.[0]?.id);

  const chat_id =
    reg.chat_id ?? regWrap.chat_id ?? seed.chat_id ?? extraer.chat_id ?? null;

  if (chat_id && tid) {
    const horasId = horasIdDesdeRegistro(reg, httpHoras);
    return {
      chat_id,
      user_id: reg.user_id ?? regWrap.user_id,
      user_name: reg.user_name ?? regWrap.user_name,
      plataforma: reg.plataforma ?? regWrap.plataforma ?? 'telegram',
      canal_respuesta: reg.canal_respuesta ?? reg.plataforma ?? 'telegram',
      resumen_creado: {
        tarea_id: tid,
        tarea: reg.tarea || seed.tarea || extraer.result?.[0]?.name || '',
        proyecto: reg.proyecto || seed.proyecto || '',
        horas: reg.horas,
        descripcion: reg.descripcion,
        horas_id: horasId,
        fecha: new Date().toISOString().split('T')[0],
        db: reg.db || 'lsanchezgoshawk-botpartesdetrabajo-main-32341811',
      },
    };
  }

  return {};
}

const r = fuenteResumenParaMarcarHecha();
