return await (async () => {
  const prep = $('Preparar Odoo Marcar Tarea FSM').first()?.json ?? {};

  const abort = (msg) => ({
    marcar_abort: true,
    ok: false,
    respuesta_usuario: msg,
    chat_id: prep.chat_id,
    plataforma: prep.plataforma,
    canal_respuesta: prep.canal_respuesta,
  });

  if ($json.error) {
    const msg = $json.error.data?.message || $json.error.message || JSON.stringify($json.error);
    return abort(`❌ No pude autenticar en Odoo: ${msg}`);
  }

  const uid = $json.result;
  if (!uid) {
    return abort('❌ No pude autenticar en Odoo.');
  }

  const url = prep.url || 'https://lsanchezgoshawk-botpartesdetrabajo.odoo.com/jsonrpc';
  const db = prep.db;
  const password = prep.odoo_password || 'admin';
  const taskId = prep.taskId;

  const rpc = async (model, method, args, kwargs = {}) => {
    const body = {
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [db, uid, password, model, method, args, kwargs],
      },
      id: Math.floor(Math.random() * 1e6),
    };
    const res = await this.helpers.httpRequest({ method: 'POST', url, body, json: true });
    if (res?.error) {
      const msg = res.error.data?.message || res.error.message || JSON.stringify(res.error);
      throw new Error(msg);
    }
    return res.result;
  };

  try {
    const tasks = await rpc('project.task', 'read', [[taskId], ['project_id', 'name']]);
    const task = tasks?.[0];
    if (!task) {
      return abort('❌ No encontré la tarea en Odoo.');
    }

    const projectId = Array.isArray(task.project_id) ? task.project_id[0] : task.project_id;
    const domain = projectId
      ? [['task_id', '=', taskId], ['project_id', '=', projectId]]
      : [['task_id', '=', taskId]];

    const allPartIds = await rpc('account.analytic.line', 'search', [domain]);
    const unsignedIds = await rpc('account.analytic.line', 'search', [[
      ...domain,
      ['customer_signed', '=', false],
    ]]);

    let signedCount = 0;
    if (Array.isArray(unsignedIds) && unsignedIds.length) {
      const now = new Date().toISOString().replace('T', ' ').slice(0, 19);
      await rpc('account.analytic.line', 'write', [unsignedIds, {
        customer_signature_date: now,
        customer_signature_name: 'Validado vía Telegram',
      }]);
      signedCount = unsignedIds.length;
    }

    await rpc(
      'project.task',
      'action_fsm_validate',
      [[taskId]],
      { context: { allow_less_hours: true } },
    );

    const tareaNombre = prep.tarea_nombre_marcar || task.name || '';
    const partesTotal = Array.isArray(allPartIds) ? allPartIds.length : 0;
    const detalleFirmas = signedCount
      ? ` (${signedCount} parte(s) marcado(s) como firmado(s))`
      : (partesTotal ? ` (${partesTotal} parte(s) ya firmado(s))` : '');

    return {
      marcar_abort: true,
      ok: true,
      respuesta_usuario: `✅ Tarea validada en Odoo${tareaNombre ? ': ' + tareaNombre : ''} (ID ${taskId})${detalleFirmas}.`,
      chat_id: prep.chat_id,
      plataforma: prep.plataforma,
      canal_respuesta: prep.canal_respuesta,
      taskId,
      tarea_nombre_marcar: tareaNombre,
      partes_firmados: signedCount,
      partes_total: partesTotal,
    };
  } catch (e) {
    return abort(`❌ Odoo no pudo validar la tarea: ${e?.message || e}`);
  }
})();

