/**
 * Rama «registrar parte de trabajo» (tras Registrar Materiales):
 * - «no he usado X» → valida contra materiales de tarea y marca no usado.
 * - «he usado como extra X» → busca en catálogo y añade línea extra a la tarea (marcada como usado).
 */
const url = 'https://lsanchezgoshawk-botpartesdetrabajo.odoo.com/jsonrpc';
const pass = 'admin';

const http = async (body) =>
  this.helpers.httpRequest({ method: 'POST', url, body, json: true });

const norm = (s) =>
  String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const normalizeTok = (s) =>
  norm(s)
    .replace(/[^a-z0-9%. ]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const STOP = new Set([
  'con', 'de', 'y', 'para', 'en', 'la', 'el', 'los', 'las', 'por', 'del', 'a', 'al',
  'no', 'he', 'usado', 'use', 'utilizado', 'utilice', 'ni', 'ha', 'como', 'extra',
]);

function variants(tok) {
  const out = new Set();
  if (!tok) return [];
  out.add(tok);
  if (tok.endsWith('es') && tok.length > 3) out.add(tok.slice(0, -2));
  if (tok.endsWith('s') && tok.length > 2) out.add(tok.slice(0, -1));
  if (tok.length >= 5 && (tok.endsWith('as') || tok.endsWith('os'))) out.add(tok.slice(0, -2));
  if (tok.length >= 4) {
    out.add(tok.slice(0, 4));
    if (tok.length >= 5) out.add(tok.slice(0, 5));
  }
  return [...out];
}

function tokens(nombre) {
  const base = normalizeTok(nombre);
  if (!base) return [];
  const raw = base.split(' ').filter((t) => t && !STOP.has(t));
  const uniq = new Set();
  for (const tk of raw) for (const v of variants(tk)) uniq.add(v);
  return [...uniq];
}

function buildProductDomain(nombreProducto) {
  const leaves = [];
  for (const tk of tokens(nombreProducto)) {
    if (tk.length < 2) continue;
    leaves.push(['name', 'ilike', tk]);
    leaves.push(['default_code', 'ilike', tk]);
  }
  const seen = new Set();
  const orLeaves = leaves.filter((l) => {
    const k = JSON.stringify(l);
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
  if (orLeaves.length === 0) return [['id', '=', -1]];
  const orTokens =
    orLeaves.length === 1 ? [orLeaves[0]] : [...Array(orLeaves.length - 1).fill('|'), ...orLeaves];
  return [['active', '=', true], ['type', 'in', ['product', 'consu']], ...orTokens];
}

function extractProductoNoUsado(texto) {
  const s = String(texto || '').trim();
  if (!s) return '';
  const pats = [
    /\by\s+no\s+se\s+ha\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+ha\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+han\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+us(?:ó|o)\s+(.+)/i,
    /\by\s+no\s+h(?:e|as)\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+h(?:e|as)\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+us(?:e|é)\s+(.+)/i,
    /\bno\s+h(?:e|as|emos|han)\s+utiliz(?:ado|amos|aron)?\s+(.+)/i,
    /\by\s+no\s+h(?:e|as)\s+utiliz(?:ado|amos)?\s+(.+)/i,
    /\bno\s+utilic(?:e|é)\s+(.+)/i,
    /\bno\s+se\s+ha\s+utilizad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+han\s+utilizad[oa]s?\s+(.+)/i,
  ];
  for (const re of pats) {
    const m = s.match(re);
    if (m?.[1]) return m[1].replace(/\s+/g, ' ').replace(/\s+[.,;:]+$/g, '').trim();
  }
  return '';
}

function extractProductoExtraUsado(texto) {
  const s = String(texto || '').trim();
  if (!s) return '';
  const pats = [
    /\by\s+he\s+usad[oa]s?\s+como\s+extra\s+(.+)/i,
    /\by\s+he\s+utilizad[oa]s?\s+como\s+extra\s+(.+)/i,
    /\bhe\s+usad[oa]s?\s+como\s+extra\s+(.+)/i,
    /\bhe\s+utilizad[oa]s?\s+como\s+extra\s+(.+)/i,
    /\bhe\s+usad[oa]s?\s+(.+?)\s+como\s+extra/i,
    /\bhe\s+utilizad[oa]s?\s+(.+?)\s+como\s+extra/i,
    /\busad[oa]s?\s+como\s+extra\s+(.+)/i,
    /\butilizad[oa]s?\s+como\s+extra\s+(.+)/i,
    /\bcomo\s+extra\s+(.+)/i,
  ];
  for (const re of pats) {
    const m = s.match(re);
    if (m?.[1]) {
      const raw = m[1].replace(/\s+/g, ' ').replace(/\s+[.,;:]+$/g, '').trim();
      if (raw.length >= 2) return raw;
    }
  }
  return '';
}

const safeFirstJson = (nodeName) => {
  try {
    const h = $(nodeName);
    if (h && typeof h.first === 'function') {
      const f = h.first();
      if (f?.json) return f.json;
    }
  } catch (_) {}
  try {
    const arr = $items(nodeName, 0);
    return arr && arr[0] ? arr[0].json : null;
  } catch (_) {
    return null;
  }
};

const parsePendientes = (raw) => {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;
  try {
    return JSON.parse(raw);
  } catch (_) {
    return {};
  }
};

function resolveTextoDeclaracion(x) {
  const prep = safeFirstJson('Preparar Datos AI Agent') || {};
  const pend = parsePendientes(prep.datos_pendientes);
  const dp = x.datos_parte || pend.datos_parte || {};
  const seed = safeFirstJson('Registrar Tarea Odoo') || {};
  const regWrap = safeFirstJson('Registrar Horas Directo FSM') || {};
  const reg = regWrap.registro || regWrap || {};

  const msgActual = String(prep.mensaje_usuario || '').trim();
  const msgActualEsSoloNumero = /^[0-9]{1,3}$/.test(msgActual);

  const candidatos = [
    x.transcripcion_original,
    x.mensaje_usuario_original,
    x.descripcion,
    dp.transcripcion_original,
    dp.mensaje_usuario_original,
    pend.datos_parte?.transcripcion_original,
    pend.datos_parte?.mensaje_usuario_original,
    reg.transcripcion_original,
    reg.transcripcion_real,
    reg.descripcion,
    seed.transcripcion_original,
    seed.mensaje_usuario_original,
    seed.datos_parte?.transcripcion_original,
    seed.datos_parte?.mensaje_usuario_original,
    prep.mensaje_usuario_original,
    !msgActualEsSoloNumero && msgActual.length > 12 ? msgActual : '',
    String(prep.mensaje_usuario || '').length > 20 ? prep.mensaje_usuario : '',
  ];

  const vistos = new Set();
  const partes = [];
  for (const c of candidatos) {
    const t = String(c || '').trim();
    if (!t || vistos.has(t)) continue;
    vistos.add(t);
    partes.push(t);
  }
  return partes.join('\n');
}

const lineProductId = (m) => {
  const v = m?.product_id;
  return Array.isArray(v) ? Number(v[0]) : Number(v);
};

const isPendingEstado = (m) => {
  const e = norm(String(m?.state ?? ''));
  return e === 'pending' || e === 'pendiente' || e.endsWith('_pending');
};

const isDoneEstado = (m) => {
  const e = norm(String(m?.state ?? ''));
  return e === 'done' || e === 'used' || e === 'usado' || e === 'hecho';
};

const isNotUsedEstado = (m) => {
  const e = norm(String(m?.state ?? ''));
  return e === 'not_used' || e === 'unused' || e === 'no_used' || e === 'no_usado';
};

const estadoLineaTxt = (m) => {
  const raw = String(m?.state ?? '').trim();
  const e = norm(raw || '');
  if (e === 'pending' || e === 'pendiente') return 'pendiente';
  if (isDoneEstado(m)) return 'usado/hecho';
  if (isNotUsedEstado(m)) return 'no usado';
  return raw || '—';
};

