  if (msg.text) {
    mensaje = msg.text.trim();
  } else if (msg.voice) {
    esAudio = true;
    fileId = msg.voice.file_id;
    mensaje = '[Mensaje de voz recibido. Transcribiendo...]';
  } else if (msg.document) {
    const d = msg.document;
    const isImageDoc = typeof d.mime_type === 'string' && d.mime_type.startsWith('image/');

    if (isImageDoc) {
      tieneImagen = true;
