        message_date_unix: msg.date || null,
        timestamp: nowIso(),
        from_chat_id: chatId,
        from_user_id: userId,
      };
    } else {
      mensaje = '[Documento recibido (no imagen)]';
    }
  } else if (msg.photo && Array.isArray(msg.photo) && msg.photo.length) {
    const photoData = msg.photo[msg.photo.length - 1];
    tieneImagen = true;
    imagenFileId = photoData.file_id;
    mensaje = caption ? caption : '[Imagen recibida sin texto]';

    imgData = {
      kind: 'photo',
      file_id: photoData.file_id,
      file_unique_id: photoData.file_unique_id,
      file_size: photoData.file_size,
      width: photoData.width,
      height: photoData.height,
      all_sizes: msg.photo,
      caption: caption || null,
      message_id: msg.message_id,
      message_date_unix: msg.date || null,
      timestamp: nowIso(),
      from_chat_id: chatId,
      from_user_id: userId,
    };
  } else if (msg.location && msg.location.latitude !== undefined && msg.location.longitude !== undefined) {
    const lat = msg.location.latitude;
    const lon = msg.location.longitude;

    mensaje = `fichar ubicacion: ${lat}, ${lon}`;
    tieneImagen = true;

    imgData = {
      kind: 'location',
      latitude: lat,
