    mensaje = waMsg.text?.body?.trim() || '';
  } else if (tipo === 'audio') {
    esAudio = true;
    fileId = waMsg.audio?.id || null;
    mensaje = '[Mensaje de voz recibido. Transcribiendo...]';
  } else if (tipo === 'image') {
    tieneImagen = true;
    imagenFileId = waMsg.image?.id || null;
    mensaje = waMsg.image?.caption?.trim() || '[Imagen recibida sin texto]';

    imgData = {
      kind: 'image',
      file_id: imagenFileId,
      mime_type: waMsg.image?.mime_type || null,
      sha256: waMsg.image?.sha256 || null,
      caption: waMsg.image?.caption || null,
      wa_message_id: waMsg.id || null,
      timestamp: nowIso(),
      from_chat_id: from,
      from_user_id: from,
    };
  } else if (tipo === 'document') {
    mensaje = waMsg.document?.caption?.trim() || '[Documento recibido]';
    fileId = waMsg.document?.id || null;
  } else if (tipo === 'location' && waMsg.location?.latitude !== undefined && waMsg.location?.longitude !== undefined) {
    const lat = Number(waMsg.location.latitude);
    const lon = Number(waMsg.location.longitude);

    mensaje = `fichar ubicacion: ${lat}, ${lon}`;
    tieneImagen = true;

    imgData = {
      kind: 'location',
      latitude: lat,
      longitude: lon,
      name: waMsg.location?.name || null,
      address: waMsg.location?.address || null,
      wa_message_id: waMsg.id || null,
      timestamp: nowIso(),
      from_chat_id: from,
      from_user_id: from,
    };
  } else {
    mensaje = `[Mensaje WhatsApp no soportado: ${tipo}]`;
  }

  return {
    plataforma: 'whatsapp',
    canal_respuesta: 'whatsapp',

    mensaje_usuario: mensaje,
    chat_id: from,           // lo reutilizas como destinatario para WhatsApp
    user_id: from,
    user_name: userName,
    timestamp: nowIso(),

    es_audio: esAudio,
