// Formatear resumen personalizado: FSM hoy (project.task) + tareas ayer (account.analytic.line)
const tareasAyerRespuesta = $json.result || [];
const datosTareas = $('Preparar Consulta Tareas Ayer').first().json;

// OJO: aquí "eventos_personalizados" ahora realmente son tareas FSM de hoy (project.task)
