});

// Formatear fecha de tareas (ayer o viernes)
const fechaTareasFormateada = new Date(fechaTareas).toLocaleDateString('es-ES', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// FUNCIÓN PARA CONVERTIR UTC A HORA LOCAL ESPAÑOLA
const convertirUTCaHoraLocal = (fechaString) => {
  if (!fechaString) return '--:--';

  try {
    // Forzamos UTC porque Odoo suele devolver sin zona
    const fechaUTC = new Date(fechaString + 'Z');
    return fechaUTC.toLocaleTimeString('es-ES', {
      hour: '2-digit',
      minute: '2-digit',
      timeZone: 'Europe/Madrid'
    });
  } catch (error) {
    console.log('❌ Error convirtiendo hora:', error);
    return '--:--';
  }
};

// =====================
// SECCIÓN: PLANIFICACIÓN HOY (FSM / project.task)
// =====================
let seccionEventos = `🛠️ **TU PLANIFICACIÓN PARA ${fechaFormateada.toUpperCase()}**\n\n`;

if (!Array.isArray(eventosPersonalizados) || eventosPersonalizados.length === 0) {
  seccionEventos += '🌟 **¡Día libre!** No tienes tareas planificadas\n\n';
} else {
  seccionEventos += `📋 **Tienes ${eventosPersonalizados.length} tarea(s) planificada(s):**\n\n`;

  eventosPersonalizados.forEach((evento, index) => {
    // evento = project.task
    const inicio = convertirUTCaHoraLocal(evento.planned_date_begin);
    const fin = convertirUTCaHoraLocal(evento.date_deadline);

    const cliente = evento.partner_id?.[1] || null;
    const proyecto = evento.project_id?.[1] || null;
    const etapa = evento.stage_id?.[1] || null;

    seccionEventos += `${index + 1}. **${evento.name || 'Sin título'}**\n`;
    seccionEventos += `   🕐 ${inicio} - ${fin}`;

    // Cliente (en vez de location)
    if (cliente) {
      seccionEventos += ` | 📍 ${cliente}`;
    }

    // Info extra útil (opcional y corta)
    const extras = [];
    if (proyecto) extras.push(`📁 ${proyecto}`);
    if (etapa) extras.push(`🏷️ ${etapa}`);
    if (extras.length) {
      seccionEventos += `\n   ${extras.join(' | ')}`;
    }

    seccionEventos += '\n\n';
  });
}

// =====================
// SECCIÓN: TAREAS AYER (NO TOCAR, ya funciona)
// =====================
const tituloTareas = esLunes
  ? `📊 **TUS TAREAS DEL ${fechaTareasFormateada.toUpperCase()}** 📅 (último día laboral)`
  : `📊 **TUS TAREAS DEL ${fechaTareasFormateada.toUpperCase()}**`;

let seccionTareas = `${tituloTareas}\n\n`;

if (errorUid || tareasAyerRespuesta.length === 0) {
  seccionTareas += '⚠️ **No se encontraron tareas registradas**\n\n';
} else {
  // Agrupar tareas por proyecto
  const tareasPorProyecto = {};
  let totalHoras = 0;

  tareasAyerRespuesta.forEach(tarea => {
    const proyectoNombre = tarea.project_id ? tarea.project_id[1] : 'Sin proyecto';
    const tareaInfo = tarea.task_id ? ` - ${tarea.task_id[1]}` : '';
    const descripcion = tarea.name || 'Sin descripción';
    const horas = tarea.unit_amount || 0;

    totalHoras += horas;

    if (!tareasPorProyecto[proyectoNombre]) {
      tareasPorProyecto[proyectoNombre] = [];
    }

    tareasPorProyecto[proyectoNombre].push({
      tarea: tareaInfo,
      descripcion: descripcion,
      horas: horas
    });
  });

  seccionTareas += `⏱️ **Total: ${totalHoras.toFixed(2)} horas registradas**\n\n`;

  Object.keys(tareasPorProyecto).forEach((proyecto, index) => {
    const tareas = tareasPorProyecto[proyecto];
    const horasProyecto = tareas.reduce((sum, t) => sum + t.horas, 0);

    seccionTareas += `${index + 1}. **${proyecto}** (${horasProyecto.toFixed(2)}h)\n`;

    tareas.forEach(tarea => {
      seccionTareas += `   • ${tarea.descripcion}${tarea.tarea} - ${tarea.horas}h\n`;
    });

    seccionTareas += '\n';
  });
}

// Resumen final
