// Extraer SOLO el correo del mensaje
const datosExtraer = $('Extraer Datos').item.json;
const mensaje = String(datosExtraer.mensaje_usuario || '').trim();

const plataforma = String(datosExtraer.plataforma || 'telegram').toLowerCase().trim();
const canalEnvio = plataforma;

const rawChatId = datosExtraer.chat_id ?? null;
const rawTelegramChatId = datosExtraer.telegram_chat_id ?? rawChatId;
const rawWhatsappPhone = datosExtraer.whatsapp_phone ?? rawChatId;

const telegramChatId =
  plataforma === 'telegram' &&
  rawTelegramChatId != null &&
  String(rawTelegramChatId).trim() !== ''
    ? Number(rawTelegramChatId)
    : null;

const whatsappPhone =
  plataforma === 'whatsapp' &&
  rawWhatsappPhone != null &&
  String(rawWhatsappPhone).trim() !== ''
    ? String(rawWhatsappPhone).replace(/\D/g, '').trim()
    : null;

// Patrón: mi correo es X
const regex = /^mi\s+correo\s+(?:es|:)\s*([^ \t@]+@[^ \t@]+\.[^ \t@]+)\s*$/i;
const match = mensaje.match(regex);

if (!match) {
  console.log('❌ No coincide con el patrón de correo simple');
  console.log('Mensaje recibido:', mensaje);
  return {
    ...datosExtraer,
    plataforma,
    canal_envio: canalEnvio,
    telegram_chat_id: telegramChatId,
    whatsapp_phone: whatsappPhone,
    correo_invalido: true,
    correo_valido: false,
    error_mensaje: 'Formato inválido. Usa: mi correo es tu@email.com',
  };
}

const correo = match[1].trim();

console.log('✅ Correo extraído:', correo);

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(correo)) {
  console.log('❌ Formato de correo inválido:', correo);
  return {
    ...datosExtraer,
    plataforma,
    canal_envio: canalEnvio,
