const norm = (s) =>
  String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const STOP = new Set(['con', 'de', 'y', 'para', 'en', 'la', 'el', 'los', 'las', 'por', 'del', 'a', 'al']);

function variants(tok) {
  const out = new Set();
  if (!tok) return [];
  out.add(tok);
  if (tok.endsWith('es')) out.add(tok.slice(0, -2));
  if (tok.endsWith('s')) out.add(tok.slice(0, -1));
  if (tok.length >= 4) {
    out.add(tok.slice(0, 4));
    if (tok.length >= 5) out.add(tok.slice(0, 5));
  }
  return [...out];
}

function tokens(nombre) {
  const base = norm(nombre).replace(/[^a-z0-9%. ]+/g, ' ').replace(/\s+/g, ' ').trim();
  if (!base) return [];
  const raw = base.split(' ').filter((t) => t && !STOP.has(t));
  const uniq = new Set();
  for (const tk of raw) for (const v of variants(tk)) uniq.add(v);
  return [...uniq];
}

function levenshtein(a, b) {
  a = norm(a);
  b = norm(b);
  const m = a.length,
    n = b.length;
  if (m === 0) return n;
  if (n === 0) return m;
  const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[i][j] = Math.min(dp[i - 1][j] + 1, dp[i][j - 1] + 1, dp[i - 1][j - 1] + cost);
    }
  }
  return dp[m][n];
}

function similarity(a, b) {
  const la = norm(a),
    lb = norm(b);
  if (!la || !lb) return 0;
  if (la === lb) return 1;
  const maxLen = Math.max(la.length, lb.length);
  const ld = levenshtein(la, lb);
  return 1 - ld / Math.max(1, maxLen);
}

function buildDomain(productosSolicitados) {
  let leaves = [];
  for (const p of productosSolicitados) {
    for (const tk of tokens(p.nombre)) {
      if (tk.length < 2) continue;
      leaves.push(['name', 'ilike', tk]);
      leaves.push(['default_code', 'ilike', tk]);
    }
  }
  const seen = new Set();
  leaves = leaves.filter((l) => {
    const k = JSON.stringify(l);
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
  let domain;
  if (leaves.length === 0) domain = [['id', '=', -1]];
  else {
    const orTokens = leaves.length === 1 ? [leaves[0]] : [...Array(leaves.length - 1).fill('|'), ...leaves];
    domain = [['active', '=', true], ['type', 'in', ['product', 'consu']], ...orTokens];
  }
  return domain;
}

