function matchProductos(pool, solicitados, th = 0.82) {
  const byName = new Map(pool.map((p) => [norm(p.name), p]));
  const resueltos = [];
  const faltantes = [];
  for (const sol of solicitados) {
    const nombreSolicitado = String(sol.nombre || '').trim();
    const cant = Number(sol.cantidad) > 0 ? Number(sol.cantidad) : 1;
    if (!nombreSolicitado) continue;
    const qN = norm(nombreSolicitado);
    if (byName.has(qN)) {
      const p = byName.get(qN);
      resueltos.push({ product_id: p.id, nombre: nombreSolicitado, cantidad: cant, product_name: p.name });
      continue;
    }
    let best = null;
    let bestScore = 0;
    for (const p of pool) {
      const sc = similarity(nombreSolicitado, p.name || '');
      if (sc > bestScore) {
        bestScore = sc;
        best = p;
      }
    }
    if (best && bestScore >= th) {
      resueltos.push({
        product_id: best.id,
        nombre: nombreSolicitado,
        cantidad: cant,
        product_name: best.name,
      });
    } else {
      faltantes.push({ nombre: nombreSolicitado, cantidad: cant });
    }
  }
  return { resueltos, faltantes };
}

