      reg.transcripcion_real ??
      pendientesMem?.datos_parte?.transcripcion_original ??
      pendientesMem?.datos_parte?.mensaje_usuario_original ??
      seedParte?.transcripcion_original ??
      seedParte?.mensaje_usuario_original ??
      $json.transcripcion_original ??
      $json.mensaje_usuario_original ??
      (String(memRow?.mensaje_usuario || '').length > 15 &&
      !/^[0-9]{1,3}$/.test(String(memRow.mensaje_usuario).trim())
        ? memRow.mensaje_usuario
        : null) ??
      null,
    mensaje_usuario_original:
      reg.mensaje_usuario_original ??
      pendientesMem?.datos_parte?.mensaje_usuario_original ??
      pendientesMem?.datos_parte?.transcripcion_original ??
      seedParte?.mensaje_usuario_original ??
      $json.mensaje_usuario_original ??
      null,
    odoo_user: reg.odoo_user ?? pendientesMem.odoo_user ?? $json.odoo_user ?? null,
    ...extra,
  };
};

let timesheetLineId =
