  timesheet_line_id: timesheetLineId,
  debug_paths: {
    input_productos_validados: Array.isArray($json.productos_validados) ? $json.productos_validados.length : null,
    valid_productos_validados: Array.isArray(valid.productos_validados) ? valid.productos_validados.length : null,
