  if (Array.isArray(eids) && eids.length) {
    const e0 = eids[0];
    const n = Array.isArray(e0) ? Number(e0[0]) : Number(e0);
    if (Number.isFinite(n) && n > 0) employeeIdResolved = n;
  }
} catch {}

// -------------------------
// ✅ Diagnóstico
// -------------------------
const esDiagnosis =
  x.is_diagnosis_task === true ||
  datosParte.is_diagnosis_task === true ||
  pendientes.is_diagnosis_task === true ||
  false;

// -------------------------
// ✅ TRANSCRIPCIÓN (NO contaminada + no recalcular en corrección)
// -------------------------
let transcripcionCompleta = '';

if (enCorreccionProductos) {
  // ✅ En corrección: usa lo guardado (no lo machaques con "juntas"/"si")
  transcripcionCompleta =
    clean(pendientes?.transcripcion_real) ||
    clean(pendientes?.transcripcion_original) ||
    clean(descripcion) ||
    'Sin transcripción disponible';
} else {
  // ✅ MENSAJE INICIAL: SOLO de fuentes iniciales estables
  const primerMensaje =
    datosParte?.mensaje_usuario_original ||
    datosParte?.transcripcion_original ||
    pendientes?.datos_parte?.mensaje_usuario_original ||
    pendientes?.datos_parte?.transcripcion_original ||
    seed?.mensaje_usuario_original ||
    seed?.transcripcion_original ||
    seed?.datos_parte?.mensaje_usuario_original ||
    seed?.datos_parte?.transcripcion_original ||
    null;

  const memModoEsperando =
    clean(memRow.esperando_confirmacion || pendientes?.modo || '');

  const mensajeActualRaw =
    memRow?.mensaje_usuario ||
    x.mensaje_usuario ||
    prepCompleto?.message?.text ||
    prepUser?.message?.text ||
    normalizado?.message?.text ||
    x.message?.text ||
    x.body?.message?.text ||
    x.text ||
    null;

  const parseHorasFromText = (txt, opts = {}) => {
    const trimmedMsg = clean(txt).toLowerCase();
    if (!trimmedMsg) return null;

    const banal = new Set(['si', 'sí', 'ok', 'vale', 'de acuerdo', 'correcto']);
    if (banal.has(trimmedMsg)) return null;

    // Si el usuario elige una tarea de una lista («1», «2»…), ese entero corto NO son horas aquí.
    const soloEnterosCortos = /^[0-9]{1,3}$/.test(trimmedMsg.replace(/\s+/g, ''));
    const memModo = opts.memEsperando || '';
    const inicial = clean(opts.inicialMensaje || '');
    const eligiendoListaTarea =
      memModo === 'elegir_tarea_multiple' ||
      memModo === 'confirmar_tarea_unica' ||
      memModo === 'elegir_tarea_multiple_imagen_previa' ||
      /** fallback: mensaje inicial largo + sólo dígitos ahora ⇒ casi siempre elección numerada */
      (inicial.length >= 48 && soloEnterosCortos);

    if (soloEnterosCortos && eligiendoListaTarea) {
      return null;
    }

    const m = trimmedMsg.replace(',', '.').match(/(\d+(\.\d+)?)/);
    if (!m) return null;

    const n = Number(m[1]);
    return Number.isFinite(n) && n > 0 ? n : null;
  };

  const p = clean(primerMensaje);
  const inicialParaParse =
    primerMensaje ||
    pendientes?.datos_parte?.mensaje_usuario_original ||
    pendientes?.datos_parte?.transcripcion_original ||
    seed?.mensaje_usuario_original ||
    seed?.transcripcion_original ||
    '';

  const horasEnTexto = parseHorasFromText(mensajeActualRaw, {
    memEsperando: memModoEsperando,
    inicialMensaje: inicialParaParse,
  });

  const trimmedActualDigits = clean(mensajeActualRaw).replace(/\s+/g, '');
  const soloDigMsgActual = /^[0-9]{1,3}$/.test(trimmedActualDigits);
  const horasEnDatosParte = toNum(datosParte.horas ?? pendientes.datos_parte?.horas);

  let mensajeHoras = horasEnTexto !== null ? clean(mensajeActualRaw) : null;

  /**
   * Tras elegir tarea con «1», el mensaje actual no debe interpretarse como «1 hora» si ya había
   * horas en datos_parte (p.ej. 5h en el mensaje inicial).
   */
  if (
    mensajeHoras &&
    soloDigMsgActual &&
    horasEnDatosParte != null &&
    horasEnDatosParte > 0 &&
    horasEnTexto !== null &&
    horasEnTexto !== horasEnDatosParte
  ) {
    mensajeHoras = null;
  }

  if (p && mensajeHoras) {
    transcripcionCompleta = (p === mensajeHoras)
      ? p
      : `🟦 MENSAJE INICIAL:\n${p}\n\n🟩 MENSAJE HORAS:\n${mensajeHoras}`;
  } else if (p) {
    transcripcionCompleta = p; // ✅ si no hay mensaje horas válido, solo inicial
  } else if (mensajeHoras) {
    transcripcionCompleta = mensajeHoras;
  } else {
    transcripcionCompleta = clean(descripcion) || 'Sin transcripción disponible';
  }
}

const transcripcionReal = transcripcionCompleta;

// -------------------------
// ✅ Horas presupuestadas
// -------------------------
const horasPresupuestadas =
  toNum(
    x.horas_presupuestadas ||
    datosParte.horas_presupuestadas ||
    pendientes.horas_presupuestadas ||
    seed.horas_presupuestadas ||
    normalizado?.horas_presupuestadas ||
    0
  ) ?? 0;

// -------------------------

// -------------------------
// ✅ Travel fields (distancia y tiempo de desplazamiento)
// -------------------------
const travel_distance_km = toNum(
  x.travel_distance_km ||
  datosParte.travel_distance_km ||
  pendientes?.datos_parte?.travel_distance_km ||
  pendientes?.travel_distance_km ||
  seed.travel_distance_km ||
  normalizado?.travel_distance_km ||
  0
) ?? 0;

const travel_time_hours = toNum(
  x.travel_time_hours ||
  datosParte.travel_time_hours ||
  pendientes?.datos_parte?.travel_time_hours ||
  pendientes?.travel_time_hours ||
  seed.travel_time_hours ||
  normalizado?.travel_time_hours ||
  0
) ?? 0;

console.log('🚗 Travel distance_km:', travel_distance_km);
console.log('⏱️ Travel time_hours:', travel_time_hours);

// ✅ Descripción mejorada
// -------------------------
let descripcionMejorada = (descripcion || seedReg.name || `Parte - ${tareaNombre}`).trim();

if (esDiagnosis && horasPresupuestadas > 0) {
  descripcionMejorada = `${descripcionMejorada} [PRESUPUESTO: ${horasPresupuestadas}h]`;
}

if (Array.isArray(productos) && productos.length > 0) {
  const listaProductos = productos
    .map(p => `- ${p.nombre || p.product_name || 'Producto sin nombre'}: ${p.cantidad || p.quantity || 1} unidad(es)`)
    .join('\n');

  if (esDiagnosis) {
    descripcionMejorada = `${descripcionMejorada}\n\n📋 PRODUCTOS MENCIONADOS (Presupuesto):\n${listaProductos}`;
  } else {
    descripcionMejorada = `${descripcionMejorada}\n\n📦 MATERIALES UTILIZADOS:\n${listaProductos}`;
  }
}

if (transcripcionCompleta) {
  descripcionMejorada = `${descripcionMejorada}\n\n🗒️ CONTEXTO COMPLETO (OPERARIO):\n${transcripcionCompleta}`;
}

// -------------------------
// ✅ Validación IDs
// -------------------------
if (!tareaId || !proyectoId) {
  throw new Error(
    `Faltan IDs. task_id=${tareaId} project_id=${proyectoId}. ` +
    `Revisa que lleguen desde Registrar Tarea Odoo / pendientes / input.`
  );
}

// -------------------------
// ✅ Payload create (account.analytic.line) + employee_id (hr_timesheet)
// -------------------------
const urlJsonRpc = 'https://lsanchezgoshawk-botpartesdetrabajo.odoo.com/jsonrpc';

const httpRpc = async (body) =>
  this.helpers.httpRequest({
    method: 'POST',
    url: urlJsonRpc,
    body,
    json: true,
  });

const buildSalida = async () => {
  let employeeId = employeeIdResolved;

  if (!employeeId && userIdFromPerfil) {
    try {
      const rr = await httpRpc({
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'object',
          method: 'execute_kw',
          args: [
            DB,
            UID,
            PASS,
            'hr.employee',
            'search_read',
            [[['user_id', '=', Number(userIdFromPerfil)], ['active', '=', true]]],
            { fields: ['id', 'name'], limit: 5 },
          ],
        },
        id: Math.floor(Math.random() * 1e6),
      });
      const rows = Array.isArray(rr?.result) ? rr.result : [];
      if (rows.length) employeeId = rows[0].id;
    } catch (e) {
      console.log('⚠️ hr.employee search_read:', e?.message || e);
    }
  }

  if (!employeeId) {
    throw new Error(
      '❌ Falta **empleado (hr.employee) activo** vinculado a tu usuario Odoo para registrar el parte. ' +
        'Solución típica: en RR.HH crea/actívalo el empleado y enlázalo desde la **ficha Usuario** (relación usuarios-empleados), ' +
        'asignándole la **compañía** correcta del proyecto.',
    );
  }

  const valoresParte = {
    name: descripcionMejorada,
    project_id: proyectoId,
    task_id: tareaId,
    unit_amount: horas,
    date: hoy,
    transcripcion_real: transcripcionReal,
    is_diagnosis_task: esDiagnosis,
    travel_distance_km: travel_distance_km,
    travel_time_hours: travel_time_hours,
    employee_id: employeeId,
    ...(userIdFromPerfil ? { user_id: Number(userIdFromPerfil) } : {}),
  };

  const payload = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        DB,
        UID,
        PASS,
        'account.analytic.line',
        'create',
        [[valoresParte]],
      ],
    },
    id: Math.floor(Math.random() * 1e6),
  };

  return {
    payload,
    skip_registrar_horas: false,
    registro: {
      chat_id: x.chat_id || seed.chat_id || normalizado.chat_id || memRow?.chat_id,
      proyecto: proyectoNombre,
      tarea: tareaNombre,
      horas,
      horas_presupuestadas: horasPresupuestadas,
      is_diagnosis_task: esDiagnosis,
      descripcion: (descripcion || seedReg.name || `Parte - ${tareaNombre}`).trim(),
      transcripcion_original: transcripcionCompleta,
      transcripcion_real: transcripcionReal,
      task_id: tareaId,
      project_id: proyectoId,
      travel_distance_km: travel_distance_km,
      travel_time_hours: travel_time_hours,
      odoo_user: x.odoo_user || pendientes.odoo_user || seed.odoo_user || normalizado.odoo_user || memRow?.odoo_user || null,
      odoo_user_id: userIdFromPerfil || null,
      odoo_user_name: userNameFromPerfil || null,
      employee_id: employeeId,
      productos,
      db: DB,
      uid: UID,
    },
  };
};

return await buildSalida();

// ✅ Preparar Buscar Usuario Odoo (robusto para rama registrar_tarea)

const x = $json;

// helper: leer json de otro nodo si existe / se ejecutó
const safeNodeJson = (name) => {
  try {
    const it = $items(name, 0);
    return it?.[0]?.json ?? null;
  } catch {
    return null;
  }
};

// 1) Fuentes posibles
const normalizado = safeNodeJson('Normalizar Parte+Materiales FSM') || null;
const authNode = safeNodeJson('Autenticar Odoo') || null;

const memRow = safeNodeJson('Preparar Datos AI Agent') || null;

// 2) Parse seguro de datos_pendientes de Postgres
const parseJSONSafe = (v) => {
  try { return typeof v === 'string' ? JSON.parse(v) : (v || {}); }
  catch { return {}; }
};

const pendientes = parseJSONSafe(memRow?.datos_pendientes);

// 3) Credenciales / contexto (prioridad: input -> pendientes -> normalizado -> defaults)
const DB =
  x.db ||
  pendientes.db ||
  normalizado?.db ||
  'lsanchezgoshawk-botpartesdetrabajo-main-32341811';

let UID =
  x.uid_admin ||
  x.uid ||
  pendientes.uid_admin ||
  normalizado?.uid ||
  2;

// si existe Autenticar Odoo y trae result, úsalo
if (authNode?.result) UID = authNode.result;

const PASS =
  x.pass_admin ||
  pendientes.pass_admin ||
  'admin';

// 4) Email del usuario final (muy importante)
const email =
  x.odoo_user ||
  pendientes.odoo_user ||
  normalizado?.odoo_user ||
  memRow?.odoo_user ||
  '';

// Si no hay email, NO rompas el flujo: devuelve skip para que lo bypasses
if (!email) {
  return {
    ...x,
    db: DB,
    uid: UID,
    pass_admin: PASS,
    skip_user_lookup: true,
    motivo: 'Falta odoo_user/email para buscar res.users',
  };
}

// 5) Payload JSON-RPC
const payload = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      DB, UID, PASS,
      'res.users', 'search_read',
      [[
        '|',
        ['login', '=', email],
        ['email', '=', email],
      ]],
      { fields: ['id', 'name', 'login', 'email', 'partner_id', 'employee_ids'], limit: 1 },
    ],
  },
  id: Math.floor(Math.random() * 1e6),
};

return {
  ...x,
  db: DB,
  uid: UID,
  pass_admin: PASS,
  odoo_user: email,
  payload,
};

// Log para datos inválidos que no se pueden guardar en PostgreSQL
console.log('❌ DATOS INVÁLIDOS - No se guardó en PostgreSQL:');
console.log('📄 Datos recibidos:', JSON.stringify($json, null, 2));
console.log('🚫 Razón:', $json.razon || 'No especificada');
console.log('📊 Chat ID original:', $json.chat_id_original);
console.log('🔢 Chat ID numérico:', $json.chat_id_numerico);

return { 
  mensaje: 'Datos no guardados en PostgreSQL por ser inválidos',
  detalles: $json 
};

