// NODO UNIFICADOR - PREPARAR DATOS POSTGRESQL CON BÚSQUEDA ACTIVA
const timestampActual = new Date().toISOString();

// ✅ RAMA COMPRA INV: Telegram/WhatsApp devuelven solo la respuesta de la API; recuperar contexto del nodo anterior
let compraInvCtx = {};
try {
  const rc = $('Registro Compra Inventario Odoo').first()?.json;
  if (rc && String(rc.esperando_confirmacion || '').startsWith('compra_inv_')) {
    compraInvCtx = rc;
  }
} catch (e) {
  console.log('ℹ️ Sin contexto Registro Compra Inventario Odoo:', e.message);
}

// Detectar si viene del flujo de evento incompleto
let respuestaBot = compraInvCtx.respuesta_usuario || $json.texto_final || $json.texto || $json.text || $json.respuesta_usuario || 'Respuesta procesada';

// Si viene de evento incompleto, usar mensaje específico
if ($json.esperando_confirmacion === 'crear_evento_calendario' && $json.datos_pendientes) {
  respuestaBot = 'faltan datos';
} else if ($json.ultimo_mensaje_bot) {
  respuestaBot = $json.ultimo_mensaje_bot;
}

console.log('🔄 === PREPARAR DATOS POSTGRESQL - BÚSQUEDA ACTIVA ===');
console.log('📥 Datos recibidos directamente:', JSON.stringify($json, null, 2));

// FUNCIÓN PARA BUSCAR DATOS DEL USUARIO EN NODOS ANTERIORES
function buscarDatosUsuario() {
  const nodosABuscar = [
    'Router de Acciones FIXED',
    'Procesar Respuesta',
    'Preparar Datos AI Agent',
    'Obtener Chat ID',
    'Extraer Datos'
  ];
  for (const nombreNodo of nodosABuscar) {
    try {
      const datos = $(nombreNodo).first().json;
      if (datos && datos.chat_id && datos.chat_id !== 'unknown') {
        console.log(`✅ Datos encontrados en: ${nombreNodo}`);
        return {
          chat_id: datos.chat_id,
          user_id: datos.user_id || datos.chat_id,
          user_name: datos.user_name || 'Usuario',
          mensaje_original: datos.mensaje_usuario || datos.mensaje_original || 'mensaje no disponible',
          fuente: nombreNodo,
          es_fallback: datos.es_fallback === true
        };
      }
    } catch (e) {
      console.log(`⚠️ No se pudo acceder a ${nombreNodo}:`, e.message);
    }
  }
  return null;
}

// INTENTAR OBTENER DATOS DEL USUARIO
let datosUsuario = {
  chat_id: compraInvCtx.chat_id ?? $json.chat_id,
  user_id: compraInvCtx.user_id ?? $json.user_id,
  user_name: compraInvCtx.user_name ?? $json.user_name,
  mensaje_original: $json.mensaje_usuario || $json.mensaje_original,
  es_fallback: $json.es_fallback === true
};

// Si no tenemos chat_id válido, buscar en nodos anteriores
if (!datosUsuario.chat_id || datosUsuario.chat_id === 'unknown') {
  console.log('🔍 Chat ID no válido, buscando en nodos anteriores...');
  const datosBuscados = buscarDatosUsuario();
  if (datosBuscados) {
    datosUsuario = datosBuscados;
    console.log(`✅ Datos recuperados desde: ${datosBuscados.fuente}`);
  } else {
    console.log('❌ No se encontraron datos válidos del usuario');
    datosUsuario = {
      chat_id: 0,
      user_id: 0,
      user_name: 'unknown',
      mensaje_original: 'mensaje no disponible',
      fuente: 'fallback',
      es_fallback: true
    };
  }
}

console.log('👤 DATOS FINALES DEL USUARIO:', {
  chat_id: datosUsuario.chat_id,
  user_id: datosUsuario.user_id,
  user_name: datosUsuario.user_name,
  fuente: datosUsuario.fuente || 'directo',
  es_fallback: datosUsuario.es_fallback === true
});

// PRESERVAR esperando_confirmacion cuando venimos de máquina/coche esperando respuesta del usuario
let esperandoPreservar = null;
let datosPendientesPreservar = null;
const estadosPreservarMaq = ['elegir_maquina_usar', 'elegir_maquina_liberar', 'confirmar_usar_maquina_cambio'];
const estadosPreservarCoche = ['confirmar_usar_coche_cambio', 'elegir_coche_usar', 'elegir_coche_liberar'];
try {
  const procMaq = $('Procesar Uso Liberar Maquina').first().json;
  if (procMaq?.esperando_confirmacion && estadosPreservarMaq.includes(procMaq.esperando_confirmacion)) {
    esperandoPreservar = procMaq.esperando_confirmacion;
    datosPendientesPreservar = JSON.stringify({ maquinas_mias: procMaq.maquinas_mias || [], maquinas_libres: procMaq.maquinas_libres || [], tool_id: procMaq.tool_id, maquina_name: procMaq.maquina_name, user_id: procMaq.user_id });
  }
} catch {}
if (!esperandoPreservar) {
  try {
    const procCoche = $('Procesar Uso Liberar Coche').first().json;
    if (procCoche?.esperando_confirmacion && estadosPreservarCoche.includes(procCoche.esperando_confirmacion)) {
      esperandoPreservar = procCoche.esperando_confirmacion;
      datosPendientesPreservar = JSON.stringify({ coches_mios: procCoche.coches_mios || [], coches_libres: procCoche.coches_libres || [], vehicle_id: procCoche.vehicle_id, vehicle_name: procCoche.vehicle_name, partner_id: procCoche.partner_id });
    }
  } catch {}
}


// ✅ Material no usado: memoria al listar tareas; limpiar tras marcar en Odoo
try {
  const mm = $('Material Marcar No Usado FSM').first()?.json;
  if (
    mm &&
    mm.datos_pendientes &&
    (mm.esperando_confirmacion === 'material_marcar_no_usado_elegir_tarea' ||
      mm.esperando_confirmacion === 'material_marcar_no_usado_pedir_nombre_tarea' ||
      mm.esperando_confirmacion === 'marcar_tarea_tras_parte')
  ) {
    esperandoPreservar = mm.esperando_confirmacion;
    datosPendientesPreservar =
      typeof mm.datos_pendientes === 'string'
        ? mm.datos_pendientes
        : JSON.stringify(mm.datos_pendientes || {});
    respuestaBot = mm.respuesta_usuario || respuestaBot;
  }
  if (mm && mm.limpiar_confirmacion === true) {
    esperandoPreservar = null;
    datosPendientesPreservar = null;
  }
} catch (e) {
  console.log('ℹ️ Contexto Material no usado:', e.message);
}
// CREAR REGISTRO PARA POSTGRESQL (preservar esperando_confirmacion si máquina/coche esperando respuesta)
const registroPostgreSQL = {
  chat_id: parseInt(datosUsuario.chat_id) || 0,
  user_id: parseInt(datosUsuario.user_id) || 0,
  user_name: datosUsuario.user_name === 'unknown' ? null : datosUsuario.user_name,
  proyecto_anterior: null,
  tarea_anterior: null,
  ultima_accion: 'conversar',
  esperando_confirmacion: esperandoPreservar,
  esperando_respuesta: null,
  ultimo_mensaje_bot: respuestaBot,
  mensaje_usuario: datosUsuario.mensaje_original === 'mensaje no disponible' ? null : datosUsuario.mensaje_original,
  datos_pendientes: datosPendientesPreservar,
  historial: JSON.stringify([{
    timestamp: timestampActual,
    usuario: datosUsuario.mensaje_original,
    bot: respuestaBot,
    accion: 'conversar'
  }]),
  historial_conversacion: JSON.stringify([{
    timestamp: timestampActual,
    contenido: datosUsuario.mensaje_original,
    tipo: 'usuario'
  }, {
    timestamp: timestampActual,
    contenido: respuestaBot,
    tipo: 'bot'
  }]),
  // Propagar al post-descontar
  es_fallback: datosUsuario.es_fallback === true
};

const _ecCompra = compraInvCtx.esperando_confirmacion || $json.esperando_confirmacion;
const _dpCompra = compraInvCtx.datos_pendientes ?? $json.datos_pendientes;
if (_ecCompra && String(_ecCompra).startsWith('compra_inv_')) {
  registroPostgreSQL.esperando_confirmacion = _ecCompra;
  registroPostgreSQL.datos_pendientes =
    typeof _dpCompra === 'string' ? _dpCompra : JSON.stringify(_dpCompra || {});
}
if (compraInvCtx.limpiar_confirmacion_compra_inv === true || $json.limpiar_confirmacion_compra_inv === true) {
  registroPostgreSQL.esperando_confirmacion = null;
  registroPostgreSQL.datos_pendientes = null;
}

console.log('📤 REGISTRO FINAL PARA POSTGRESQL:', {
  chat_id: registroPostgreSQL.chat_id,
  user_id: registroPostgreSQL.user_id,
  user_name: registroPostgreSQL.user_name,
  es_fallback: registroPostgreSQL.es_fallback
