};

// Escape seguro para Markdown (usaremos backticks en nombres)
const clean = (s) => String(s ?? '').replace(/`/g, "'");

// Datos base
const resProj   = getNodeJson('Resolver Proyecto / Desambiguar');
const httpTasks = getNodeJson('HTTP Get Tareas');
const httpHours = getNodeJson('HTTP Horas por Tarea');
const httpTs    = getNodeJson('HTTP Timesheets Detalle');

const project    = resProj?.project || $json.project || {};
const tasks      = (httpTasks?.body?.result) || httpTasks?.result || $json.tasks_full || [];
const hoursGroup = ($json.body?.result) || $json.result || httpHours?.body?.result || httpHours?.result || [];
const timesheets = (httpTs?.body?.result) || httpTs?.result || [];

const baseUrl = 'https://lsanchezgoshawk-azordatatest.odoo.com';
const today   = new Date().toISOString().slice(0,10);

// Mapa horas por tarea (read_group)
const hoursByTask = {};
for (const g of (hoursGroup || [])) {
  const tid = Array.isArray(g.task_id) ? g.task_id[0] : g.task_id;
  if (!tid) continue;
  const v = (g['unit_amount'] ?? g['unit_amount:sum'] ?? 0);
  hoursByTask[tid] = Number(v) || 0;
}

// KPI globales
let plan = 0, eff = 0;
for (const t of tasks) {
  if (typeof t.planned_hours === 'number') plan += Number(t.planned_hours || 0);
  eff += Number(hoursByTask[t.id] || t.effective_hours || 0);
}
const avance = plan > 0 ? Math.min(100, Math.max(0, Math.round((eff/plan)*100))) : null;

// Barra de progreso (10 bloques)
const progressBar = (pct) => {
  const total = 10;
  const filled = Math.round((pct/100)*total);
  return '▰'.repeat(filled) + '▱'.repeat(total - filled);
};

// Icono por etapa / estado + retraso
const stageIcon = (stageName, isLate) => {
  const s = String(stageName || '').toLowerCase();
  const base = s.includes('done') || s.includes('hecho') ? '✅'
             : s.includes('progress') || s.includes('en ') ? '🚧'
             : '🆕';
  return isLate ? '⏰' : base;
};

// Cabecera
let texto = `🗂️ *Proyecto:* \`${clean(project?.name || '—')}\`\n`;
texto += `👤 *Cliente:* \`${clean(project?.partner_id ? project.partner_id[1] : '—')}\`  •  👨‍💼 *PM:* \`${clean(project?.user_id ? project.user_id[1] : '—')}\`\n`;
texto += `🗓️ *Fechas:* inicio \`${clean(project?.date_start || '—')}\` · fin prevista \`${clean(project?.date || '—')}\`\n`;

if (plan > 0) {
  texto += `⏱️ *Horas:* plan \`${plan}h\` · efectivas \`${eff}h\` · avance \`${avance}%\`\n`;
  texto += `   ${progressBar(avance)}\n`;
} else {
  texto += `⏱️ *Horas:* efectivas \`${eff}h\`\n`;
}

if (project?.id) {
  texto += `🔗 [Abrir proyecto](${baseUrl}/web#id=${project.id}&model=project.project&view_type=form)\n`;
}

texto += `\n📋 *Tareas (${tasks.length}):*\n`;

// Filas de tareas (máx 25 para no saturar Telegram)
const MAX_ROWS = 25;
const rows = [];
for (const t of tasks.slice(0, MAX_ROWS)) {
  const etapa = Array.isArray(t.stage_id) ? t.stage_id[1] : null;

  // Horas hechas
  const hechas = (typeof t.effective_hours === 'number') ? t.effective_hours : (hoursByTask[t.id] || 0);

  // Plan y restantes (si existe planned_hours)
  const tienePlan = typeof t.planned_hours === 'number';
  const rest = tienePlan ? Math.max(0, Number(t.planned_hours || 0) - Number(hechas || 0)) : null;

  // Retraso (si no está done/hecho y deadline vencida)
  const isDone = (String(etapa||'').toLowerCase().includes('done') || String(etapa||'').toLowerCase().includes('hecho'));
  const isLate = (t.date_deadline && t.date_deadline < today && !isDone);

  const icon = stageIcon(etapa, isLate);
  const link = t.id ? `  🔗 [Abrir](${baseUrl}/web#id=${t.id}&model=project.task&view_type=form)` : '';

  let line1 = `${icon} *\`${clean(t.name)}\`*  —  \`${clean(etapa || '—')}\``;
  let line2 = `   · ⏱️ \`Hechas ${hechas}h\`` + (tienePlan ? ` · \`Plan ${t.planned_hours||0}h\` · \`Rest. ${rest}h\`` : ``);
  if (t.date_deadline) line2 += ` · 🗓️ \`${t.date_deadline}\``;
  const line3 = link;

  rows.push(`${line1}\n${line2}${line3 ? `\n${line3}` : ''}`);
}
if (rows.length) texto += rows.join('\n') + (tasks.length > MAX_ROWS ? `\n… \`${tasks.length - MAX_ROWS}\` más` : '');
else texto += '—';

// Bloque de timesheets (si hay)
if (Array.isArray(timesheets) && timesheets.length) {
  // Índice por tarea + ordenar por fecha desc
  const tsByTask = {};
  for (const l of timesheets) {
    const tid = Array.isArray(l.task_id) ? l.task_id[0] : l.task_id;
    if (!tid) continue;
    (tsByTask[tid] ||= []).push(l);
  }
  for (const k of Object.keys(tsByTask)) tsByTask[k].sort((a,b)=> a.date < b.date ? 1 : -1);

  texto += `\n\n🧾 *Registros recientes (máx. 3 por tarea):*\n`;
  for (const t of tasks) {
    const ts = (tsByTask[t.id] || []).slice(0,3);
    if (!ts.length) continue;
    const lines = ts.map(x=>{
      const who = (Array.isArray(x.user_id) ? x.user_id[1] :
                  (Array.isArray(x.employee_id) ? x.employee_id[1] : '—'));
      return `   · \`${x.date || '—'}\` · \`${clean(who)}\` · \`${x.unit_amount || 0}h\` · ${clean(x.name || '')}`;
    });
    texto += `• *\`${clean(t.name)}\`*\n${lines.join('\n')}\n`;
  }
}

// chat_id desde cualquier nodo previo

const chatId =
  getNodeJson('Preparar Horas Agrupadas')?.chat_id ||
  getNodeJson('Preparar Get Tareas')?.chat_id ||
  getNodeJson('Resolver Proyecto / Desambiguar')?.chat_id ||
  $json.chat_id || 0;

// ===== Split en chunks compatibles con Telegram =====
// 4096 es el límite; dejo margen por Markdown/enlaces
const MAX = 3800;

// parte por líneas para no romper Markdown a mitad de una línea
const lines = String(texto || '').split('\n');

const chunks = [];
let buf = '';

for (const line of lines) {
  // si una sola línea es enorme, la troceamos a pelo
  if (line.length > MAX) {
    if (buf) { chunks.push(buf); buf = ''; }
    for (let i = 0; i < line.length; i += MAX) {
