    /\by\s+no\s+se\s+ha\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+ha\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+han\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+us(?:ó|o)\s+(.+)/i,
    /\by\s+no\s+h(?:e|as)\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+h(?:e|as)\s+usad[oa]s?\s+(.+)/i,
    /\bno\s+us(?:e|é)\s+(.+)/i,
    /\bno\s+h(?:e|as|emos|han)\s+utiliz(?:ado|amos|aron)?\s+(.+)/i,
    /\by\s+no\s+h(?:e|as)\s+utiliz(?:ado|amos)?\s+(.+)/i,
    /\bno\s+utilic(?:e|é)\s+(.+)/i,
    /\bno\s+se\s+ha\s+utilizad[oa]s?\s+(.+)/i,
    /\bno\s+se\s+han\s+utilizad[oa]s?\s+(.+)/i,
  ];
  for (const re of pats) {
    const m = s.match(re);
    if (m?.[1]) return m[1].replace(/\s+/g, ' ').replace(/\s+[.,;:]+$/g, '').trim();
  }
  return '';
}

const httpHorasNode = safeFirstJson('HTTP Registrar Horas Directo FSM') || {};
const regNodeWrap = safeFirstJson('Registrar Horas Directo FSM') || {};
const regNode = regNodeWrap.registro || regNodeWrap || {};
const base = safeFirstJson('Normalizar Parte+Materiales FSM') || {};
const extraerPartnerNode = safeFirstJson('Extraer partner_id') || {};
const prepObtenerTarea = safeFirstJson('Preparar Obtener Cliente desde Tarea') || {};
const seedTarea = safeFirstJson('Registrar Tarea Odoo') || {};
const prepAI = safeFirstJson('Preparar Datos AI Agent') || {};

let pendRaw = {};
try {
  pendRaw =
    typeof prepAI.datos_pendientes === 'string'
      ? JSON.parse(prepAI.datos_pendientes || '{}')
      : prepAI.datos_pendientes || {};
} catch (_) {
  pendRaw = {};
}
const pendDatosParte = pendRaw?.datos_parte || pendRaw || {};

const textoTranscripcionRegistro = String(
  regNode.transcripcion_original ||
    regNode.transcripcion_real ||
    ''
).trim();

const textoDescripcionRegistro = String(regNode.descripcion || '').trim();

/**
 * Prioridad: memoria datos_parte (mensaje antes de «1»), transcripción del registro de horas,
 * luego descripción corta del parte.
 */
const mensajeFusion = String(
  pendDatosParte.mensaje_usuario_original ||
    pendDatosParte.transcripcion_original ||
    textoTranscripcionRegistro ||
    base.mensaje_usuario_original ||
    base.transcripcion_original ||
    prepAI.mensaje_usuario_original ||
    textoDescripcionRegistro ||
    prepAI.mensaje_usuario ||
    ''
).trim();

const textoParaDeclaracionNoMaterial = [
  mensajeFusion,
  pendDatosParte.transcripcion_original,
  pendDatosParte.mensaje_usuario_original,
  textoTranscripcionRegistro,
  textoDescripcionRegistro,
  String(base.descripcion || ''),
  String(prepAI.mensaje_usuario || ''),
].join('\n');

let horasId =
  httpHorasNode.result ??
  httpHorasNode.body?.result ??
  httpHorasNode.json?.result ??
  null;

if (Array.isArray(horasId)) horasId = horasId[0];
horasId = horasId != null ? Number(horasId) : null;

const producto_extraido_fsm =
  extractProductoNoUsado(textoParaDeclaracionNoMaterial) ||
  extractProductoExtraUsado(textoParaDeclaracionNoMaterial);

const items = $input.all();
const salida = [];

for (const { json: ctx } of items) {
  const chatId = ctx.chat_id ?? regNode.chat_id ?? base.chat_id ?? 0;

  const user_id =
    ctx.user_id ?? ctx.odoo_user_id ?? regNode.odoo_user_id ?? base.odoo_user_id ?? null;

  const user_name =
    ctx.user_name ?? ctx.odoo_user ?? regNode.odoo_user ?? base.odoo_user ?? null;

  const plataforma = ctx.plataforma ?? regNode.plataforma ?? base.plataforma ?? 'telegram';

  const canal_respuesta =
    ctx.canal_respuesta ?? regNode.canal_respuesta ?? base.canal_respuesta ?? plataforma;

  const proyectoVal =
    regNode.proyecto ??
    ctx.proyecto ??
    base.proyecto ??
    extraerPartnerNode.result?.[0]?.project_id?.[1] ??
    null;

  const proyectoId =
    ctx.proyecto_id ??
    regNode.project_id ??
    extraerPartnerNode.result?.[0]?.project_id?.[0] ??
    null;

  const tareaVal =
    regNode.tarea ?? ctx.tarea ?? base.tarea ?? extraerPartnerNode.result?.[0]?.name ?? null;

  const dbComb =
    regNode.db ?? ctx.db ?? base.db ?? 'lsanchezgoshawk-botpartesdetrabajo-main-32341811';

  const tidNum =
    toNum(regNode.task_id) ??
    toNum(ctx.task_id) ??
    toNum(ctx.tarea_id) ??
    toNum(extraerPartnerNode.task_id) ??
    toNum(prepObtenerTarea.task_id) ??
    toNum(seedTarea.tarea_id) ??
    toNum(seedTarea.datos_registrados?.task_id) ??
    toNum(pendRaw.tarea_id) ??
    toNum(extraerPartnerNode.result?.[0]?.id) ??
    null;

  const jsonResumen = {
    proyecto: proyectoVal,
    proyecto_id: proyectoId,
    tarea: tareaVal,
    tarea_id: tidNum,
    horas: regNode.horas ?? ctx.horas ?? base.horas ?? 0,
    horas_id: Number.isFinite(horasId) ? horasId : ctx.horas_id ?? null,
    descripcion: textoDescripcionRegistro || ctx.descripcion || base.descripcion || null,
    fecha: ctx.fecha_hoy ?? base.fecha_hoy ?? new Date().toISOString().split('T')[0],
    db: dbComb,
    uid: regNode.uid ?? ctx.uid ?? base.uid ?? null,
  };

  const textoDeclNo = String(textoParaDeclaracionNoMaterial || '').trim();
  const mdValidadoParte = String(ctx.material_no_usado_resumen_md || '').trim();
  const yaValidadoEnParte =
    ctx.material_validado_en_parte === true && mdValidadoParte !== '';
  const irFsm =
    !yaValidadoEnParte &&
    Boolean(producto_extraido_fsm) &&
    Boolean(textoDeclNo) &&
    tidNum != null;

  salida.push({
    json: {
      chat_id: chatId,
      user_id,
      user_name,
      plataforma,
      canal_respuesta,
      mensaje_original_parte: mensajeFusion,
      producto_no_usado_extraido: irFsm ? producto_extraido_fsm : '',
      producto_nombre: irFsm ? producto_extraido_fsm : '',
      tarea_id: irFsm ? tidNum : jsonResumen.tarea_id,
      db: dbComb,
      ir_a_fsm_material: irFsm,
      marcar_material_tras_confirm_parte_si: irFsm,
      material_validado_en_parte: yaValidadoEnParte || !irFsm,
      material_no_usado_resumen_md: String(ctx.material_no_usado_resumen_md || '').trim(),
      resumen_creado: jsonResumen,
    },
  });
}

return salida;

