const respuestaOdoo = $json;

// ✅ Contexto “fijo” desde tu nodo clave
const ctx = $('Construir Mensaje Fichaje').item.json;

// Tipo fichaje: del decisor (más fiable) y si no, del ctx
const tipo =
  $('Decidir Entrada o Salida').item.json.tipo_fichaje ||
  ctx.tipo_fichaje ||
  'entrada';

const accionTxt = (tipo === 'salida') ? 'SALIDA REGISTRADA' : 'ENTRADA REGISTRADA';

// ✅ Chat ID (y validación)
const chatId = ctx.chat_id;
if (chatId === null || chatId === undefined || Number(chatId) === 0) {
  throw new Error(`chat_id inválido para Telegram: ${chatId}`);
}

// ✅ Nombre empleado (mejor sacarlo del nodo donde lo calculas)
const empleado =
  $('Extraer empleado').item.json.employee_name ||
  ctx.employee_name ||
  ctx.user_name ||
  'Empleado';

const hora = new Date().toLocaleTimeString('es-ES');
const lat = ctx.latitude;
const lon = ctx.longitude;

let respuesta = '';
if (respuestaOdoo.error) {
  respuesta = `❌ Error al registrar fichaje: ${respuestaOdoo.error?.data?.message || 'Error desconocido'}`;
} else {
  respuesta =
    `✅ **${accionTxt}**\n` +
    `👤 ${empleado}\n` +
    `🕐 ${hora}` +
    (lat != null && lon != null ? `\n📍 ${Number(lat).toFixed(6)}°, ${Number(lon).toFixed(6)}°` : '');
}

return {
  chat_id: chatId,
  texto: respuesta,
  tipo_fichaje: tipo,
  employee_name: empleado,
  fichaje_ok: !respuestaOdoo.error,
};

const toOdooDatetime = (d) => {
  const dt = d ? new Date(d) : new Date();
  const pad = (n) => String(n).padStart(2, '0');
  return `${dt.getFullYear()}-${pad(dt.getMonth()+1)}-${pad(dt.getDate())} ${pad(dt.getHours())}:${pad(dt.getMinutes())}:${pad(dt.getSeconds())}`;
};

return {
  ...$json,
  check_in_odoo: toOdooDatetime($json.check_in),
  check_out_odoo: $json.check_out ? toOdooDatetime($json.check_out) : null,
};

