// Preparar consulta Odoo: tareas de apertura planificadas hoy
const routerData = $('Router de Acciones FIXED').first().json;
const uid = $json.result;

if (!uid) throw new Error('Error en autenticación Odoo para LOPD');

const db = 'lsanchezgoshawk-botpartesdetrabajo-main-32341811';
const pass = 'admin';
const hoy = new Date();
const fechaHoy = hoy.toLocaleDateString('en-CA', { timeZone: 'Europe/Madrid' });
const manana = new Date(hoy);
manana.setDate(manana.getDate() + 1);
const fechaManana = manana.toLocaleDateString('en-CA', { timeZone: 'Europe/Madrid' });
const inicioDia = `${fechaHoy} 00:00:00`;
const finDia = `${fechaManana} 00:00:00`;

const domain = [
  ['planned_date_begin', '>=', inicioDia],
  ['planned_date_begin', '<', finDia],
  ['ticket_type', '=', 'apertura']
];

const payload = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      db, uid, pass,
      'project.task', 'search_read',
      [domain],
      { fields: ['id', 'name', 'project_id', 'planned_date_begin', 'partner_id'], order: 'planned_date_begin asc', limit: 50 }
    ]
  },
  id: Math.floor(Math.random() * 1e6)
};

return {
  payload,
  chat_id: routerData.chat_id,
  user_id: routerData.user_id,
  user_name: routerData.user_name,
  odoo_user: routerData.odoo_user
};

// Formatear lista de tareas LOPD y preparar para guardar estado
const tareas = $json.result || $json.body?.result || [];
const contexto = $('Preparar Consulta Tareas LOPD').first().json;
const chatId = contexto.chat_id;
const tareasOpciones = tareas.map(t => ({
  id: t.id,
  nombre_completo: t.name || 'Sin nombre',
  proyecto_id: t.project_id ? t.project_id[0] : null,
  proyecto_nombre: t.project_id ? t.project_id[1] : '',
  cliente: t.partner_id ? t.partner_id[1] : ''
}));

let mensaje;
if (tareasOpciones.length === 0) {
  mensaje = '❌ No tienes tareas de apertura planificadas para hoy. No hay nada que firmar.';
} else {
  const lista = tareasOpciones.map((t, i) =>
    `\n${i + 1}️⃣ ${t.nombre_completo}${t.cliente ? ' - ' + t.cliente : ''}`
  ).join('');
  mensaje = `📋 **Tareas de apertura de hoy para firmar LOPD:**${lista}\n\n✍️ Responde con el número (1, 2, 3...) para obtener el enlace de firma.`;
}

return {
  chat_id: chatId,
  respuesta_usuario: mensaje,
  tareas_opciones: tareasOpciones,
  cantidad: tareasOpciones.length,
  datos_pendientes: JSON.stringify({
    esperando_confirmacion: tareasOpciones.length > 0 ? 'elegir_tarea_lopd' : null,
    tareas_opciones: tareasOpciones
  })
};

const x = $json || {};
const msg = x.message || x.body?.message || null;

// Detectar document/photo en update crudo
const doc = msg?.document || null;
const photo = msg?.photo || null;

// Elegir file_id
let fileIdFinal = null;
let tipo = null;

if (doc?.file_id) {
  fileIdFinal = doc.file_id;
  tipo = 'document';
} else if (Array.isArray(photo) && photo.length && photo[photo.length - 1]?.file_id) {
  fileIdFinal = photo[photo.length - 1].file_id;
  tipo = 'photo';
} else if (x.imagen_file_id) {
  fileIdFinal = x.imagen_file_id;
  tipo = 'legacy';
} else if (x.img_data?.file_id) {
  fileIdFinal = x.img_data.file_id;
  tipo = 'legacy';
}

return {
  ...x,
  file_id_final: fileIdFinal,
  tipo_media: tipo,
  // compatibilidad con tu flow actual
  tiene_imagen: !!fileIdFinal,
};

