const entrada = ($items('Extraer Datos', 0)?.[0]?.json) || {};
const dbCheck = $json || {};

const chatIdRaw =
  entrada.chat_id ??
  entrada.from_chat_id ??
  entrada.telegram_chat_id ??
  entrada.whatsapp_phone ??
  entrada.user_id ??
  dbCheck.user_id_db ??
  null;

const chatId = chatIdRaw != null && String(chatIdRaw).trim() !== ''
  ? String(chatIdRaw).replace(/\s+/g, '').trim()
  : null;

const userIdRaw =
  entrada.user_id ??
  dbCheck.user_id_db ??
  chatIdRaw ??
  null;

const userId = userIdRaw != null && String(userIdRaw).trim() !== ''
  ? String(userIdRaw).replace(/\s+/g, '').trim()
  : chatId;

const ahora = Date.now();
const ultimoMsjAt = dbCheck.ultimo_mensaje_at ? new Date(dbCheck.ultimo_mensaje_at).getTime() : null;
const ultimoHorasAt = dbCheck.ultimo_horas_actualizado_at ? new Date(dbCheck.ultimo_horas_actualizado_at).getTime() : null;
const ventana = 60 * 60 * 1000;
const esRecienteMsj = Number.isFinite(ultimoMsjAt) && (ahora - ultimoMsjAt) <= ventana;
const esRecienteHoras = Number.isFinite(ultimoHorasAt) && (ahora - ultimoHorasAt) <= ventana;
const esReciente = esRecienteMsj || esRecienteHoras;

const esperando = String(dbCheck.esperando_confirmacion || '').toLowerCase().trim();
const ultimoBot = String(dbCheck.ultimo_mensaje_bot || '').toLowerCase();

// ⚠️ Si estamos en confirmación de imagen previa, NUNCA tratar como parte reciente
const bloqueaContextoImagen = [
  'confirmar_tarea_unica_imagen_previa',
  'elegir_tarea_multiple_imagen_previa',
].includes(esperando);

const marcasParte = [
  'confirmar_tarea_unica',
  'elegir_tarea_multiple',
  'falta_horas_registrar_tarea',
];

const ultimoHorasId = Number(dbCheck.ultimo_horas_id ?? 0);
const tieneUltimoHoras = Number.isFinite(ultimoHorasId) && ultimoHorasId > 0;
const partePorUltimoHorasDb = tieneUltimoHoras && (esRecienteMsj || esRecienteHoras);

const marcasExitoParteBot = /firma-parte|\*\*id del registro|id del registro|parte de horas|registrad[oa] exitosamente|account\.analytic\.line|entregas de material|listo.*firma/i.test(ultimoBot);

const pareceParte = !bloqueaContextoImagen && (
  marcasParte.includes(esperando)
  || /parte|tarea|horas|registro|material/.test(ultimoBot)
  || partePorUltimoHorasDb
  || marcasExitoParteBot
);

const contextoParteReciente = Boolean(esReciente && pareceParte && !bloqueaContextoImagen);

return {
  ...entrada,
  odoo_user: String(dbCheck.odoo_user || entrada.odoo_user || '').trim(),
  user_name: dbCheck.user_name_db || entrada.user_name || 'Usuario',
  user_id: userId,
  chat_id: chatId,
  telegram_chat_id: entrada.telegram_chat_id ?? null,
  whatsapp_phone: entrada.whatsapp_phone ?? null,
  db: 'lsanchezgoshawk-botpartesdetrabajo-main-32341811',
  uid: 2,
  cliente: '',
  contexto_parte_reciente: contextoParteReciente,
  _debug_contexto_imagen: {
