  }

  const url = prep.url || 'https://lsanchezgoshawk-botpartesdetrabajo.odoo.com/jsonrpc';
  const db = prep.db;
  const password = prep.odoo_password || 'admin';
  const taskId = prep.taskId;

  const rpc = async (model, method, args, kwargs = {}) => {
    const body = {
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [db, uid, password, model, method, args, kwargs],
      },
