const norm = (s) =>
  String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const normalizeTok = (s) =>
  norm(s)
    .replace(/[^a-z0-9%. ]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const STOP = new Set([
  'con', 'de', 'y', 'para', 'en', 'la', 'el', 'los', 'las', 'por', 'del', 'a', 'al',
  'no', 'he', 'usado', 'use', 'utilizado', 'utilice', 'ni', 'ha',
]);
function variants(tok) {
  const out = new Set();
  if (!tok) return [];
  out.add(tok);
  if (tok.endsWith('es') && tok.length > 3) out.add(tok.slice(0, -2));
  if (tok.endsWith('s') && tok.length > 2) out.add(tok.slice(0, -1));
  if (tok.length >= 5 && (tok.endsWith('as') || tok.endsWith('os'))) out.add(tok.slice(0, -2));
  if (tok.length >= 4) {
    out.add(tok.slice(0, 4));
    if (tok.length >= 5) out.add(tok.slice(0, 5));
  }
  return [...out];
}
function tokens(nombre) {
  const base = normalizeTok(nombre);
  if (!base) return [];
  const raw = base.split(' ').filter((t) => t && !STOP.has(t));
  const uniq = new Set();
  for (const tk of raw) for (const v of variants(tk)) uniq.add(v);
  return [...uniq];
}

function buildProductDomain(nombreProducto) {
  const leaves = [];
  for (const tk of tokens(nombreProducto)) {
    if (tk.length < 2) continue;
    leaves.push(['name', 'ilike', tk]);
    leaves.push(['default_code', 'ilike', tk]);
  }
  const seen = new Set();
  const orLeaves = leaves.filter((l) => {
    const k = JSON.stringify(l);
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
  if (orLeaves.length === 0) return [['id', '=', -1]];
  const orTokens =
    orLeaves.length === 1 ? [orLeaves[0]] : [...Array(orLeaves.length - 1).fill('|'), ...orLeaves];
  return [['active', '=', true], ['type', 'in', ['product', 'consu']], ...orTokens];
}

