/** ID numérico de product_id en líneas Odoo (many2one). */
function lineProductId(m) {
  const v = m && m.product_id;
  return Array.isArray(v) ? toNumSafe(v[0]) : toNumSafe(v);
}
function toNumSafe(v) {
  const n = Number(v);
  return Number.isFinite(n) && n > 0 ? n : null;
}
function estadoLineaTxt(m) {
  const raw = String(m?.state ?? '').trim();
  const e = norm(raw || '');
  if (e === 'pending' || e === 'pendiente') return 'pendiente';
  if (e === 'done' || e === 'used' || e === 'usado' || e === 'hecho') return 'usado/hecho';
  if (e === 'not_used' || e === 'unused' || e === 'no_used' || e === 'no_usado') return 'no usado';
  return raw || '—';
}
function isPendingEstado(m) {
  const e = norm(String(m?.state ?? ''));
  return (
    e === 'pending' ||
    e === 'pendiente' ||
    e.endsWith('_pending')
  );
}
function formatoLineaMaterial(m) {
  let nombre =
    Array.isArray(m.product_id) && m.product_id[1]
      ? String(m.product_id[1]).trim()
      : '';
  if (!nombre) {
    const pid = lineProductId(m);
    const p = pid ? prodById.get(pid) : null;
    if (p)
      nombre =
        String(p.name || '').trim() + (p.default_code ? ' [' + String(p.default_code).trim() + ']' : '');
    else nombre = pid ? 'Producto ID ' + pid : 'Sin nombre';
  }
  return nombre + ' _(estado: ' + estadoLineaTxt(m) + ')_';
}

