function pickProducto(prods, mencion) {
  if (!prods?.length) return null;
  const m = norm(mencion);
  const exact = prods.find((p) => norm(p.name) === m || norm(p.default_code || '') === m);
  if (exact) return exact;
  return prods[0];
}

function formatoLinea(m, prodById) {
  let nombre =
    Array.isArray(m.product_id) && m.product_id[1] ? String(m.product_id[1]).trim() : '';
  if (!nombre) {
    const pid = lineProductId(m);
    const p = pid ? prodById.get(pid) : null;
    nombre = p
      ? String(p.name || '').trim() + (p.default_code ? ' [' + p.default_code + ']' : '')
      : pid
        ? 'Producto ID ' + pid
        : 'Sin nombre';
  }
  const extraTag = m.is_extra ? ' _(extra)_' : '';
  return '• ' + nombre + extraTag + ' _(estado: ' + estadoLineaTxt(m) + ')_';
}

function bullets(rows, prodById, limit = 35) {
  const list = (rows || []).slice(0, limit).map((m) => formatoLinea(m, prodById));
  return list.length ? list.join('\n') : '_Sin líneas._';
}

async function procesarNoUsado(ctx) {
  const { db, uid, taskId, productoMencion, matsAll, prodById } = ctx;
  const prodIdsFound = ctx.prodIdsFound;

  const taskProductIds = new Set();
  for (const m of matsAll) {
    const pid = lineProductId(m);
    if (pid) taskProductIds.add(pid);
  }

  const productoEnTarea = [...prodIdsFound].some((id) => taskProductIds.has(id));

  if (!productoEnTarea) {
    const extra =
      ctx.prods.length > 1
        ? '\n\n_(Hay varios productos parecidos en catálogo; ninguno está en esta tarea.)_'
        : '';
    return {
      md:
        '\n\n❌ Este material («**' +
        productoMencion +
        '**») **no está entre los materiales de la tarea** donde registraste el parte.' +
        (matsAll.length
          ? '\n\n📦 **Los que sí están asignados a la tarea:**\n' + bullets(matsAll, prodById)
          : '\n\n📦 Esta tarea **no tiene líneas en «Materiales de tarea»** en Odoo (lista vacía).') +
        extra,
    };
  }

  const matsPendientes = matsAll.filter(isPendingEstado);
  const matched = matsPendientes.filter((m) => {
    const pid = lineProductId(m);
    return pid && prodIdsFound.has(pid);
  });

  if (matched.length === 0) {
    const lineasMismo = matsAll.filter((m) => {
      const pid = lineProductId(m);
      return pid && prodIdsFound.has(pid);
    });
    if (lineasMismo.length) {
      return {
        md:
          '\n\n⚠️ **Material (no usado):** «**' +
          productoMencion +
          '**» está en la tarea pero **no en estado Pendiente** (solo pendientes se marcan aquí).\n\n**Tu línea:**\n' +
          bullets(lineasMismo, prodById, 10) +
          '\n\n**Pendientes en la tarea:**\n' +
          bullets(matsPendientes, prodById, 20),
      };
    }
  }

  const lineIds = matched.map((m) => m.id);
  if (lineIds.length) {
    const r = await http({
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [db, uid, pass, 'azordata.project.task.material', 'action_mark_not_used', [lineIds]],
      },
      id: Math.floor(Math.random() * 1e6),
    });
    if (r.error) {
      return {
        md:
          '\n\n⚠️ **Material (no usado):** Odoo no pudo marcar como no usado: ' +
          (r.error.data?.message || r.error.message || ''),
      };
    }
  }

  const nombres = matched
    .map((m) => (Array.isArray(m.product_id) ? m.product_id[1] : productoMencion))
    .join(', ');

  return {
    md: matched.length
      ? '\n\n✅ **Material marcado como no usado** en esta tarea: ' + nombres + '.'
      : '\n\n⚠️ **Material (no usado):** Validación incompleta para «' + productoMencion + '».',
  };
}

async function markUsedLineIds(db, uid, lineIds) {
  const r = await http({
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [db, uid, pass, 'azordata.project.task.material', 'action_mark_used', [lineIds]],
    },
    id: Math.floor(Math.random() * 1e6),
  });
  if (r.error) {
    throw new Error(r.error.data?.message || r.error.message || JSON.stringify(r.error));
  }
}

async function procesarExtraUsado(ctx) {
  const { db, uid, taskId, productoMencion, matsAll, prodById } = ctx;
  const prod = ctx.prodElegido;
  const prodIdsFound = ctx.prodIdsFound;

  const lineasMismoProd = matsAll.filter((m) => {
    const pid = lineProductId(m);
    return pid && prodIdsFound.has(pid);
  });

  const pendientes = lineasMismoProd.filter(isPendingEstado);
  const hechas = lineasMismoProd.filter(isDoneEstado);
  const noUsadas = lineasMismoProd.filter(isNotUsedEstado);

  let lineIdsMarcar = [];

  if (pendientes.length) {
    lineIdsMarcar = pendientes.map((m) => m.id);
  } else if (!lineasMismoProd.length) {
    const uomId = Array.isArray(prod.uom_id) ? prod.uom_id[0] : prod.uom_id;
    if (!uomId) {
      return {
        md:
          '\n\n⚠️ **Material extra:** El producto «**' +
          productoMencion +
          '**» no tiene unidad de medida en Odoo.',
      };
    }

    let maxSeq = 10;
    for (const m of matsAll) {
      const s = Number(m.sequence);
      if (Number.isFinite(s)) maxSeq = Math.max(maxSeq, s);
    }

    const cr = await http({
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [
          db,
          uid,
          pass,
          'azordata.project.task.material',
          'create',
          [
            {
              task_id: taskId,
              product_id: prod.id,
              product_uom_id: uomId,
              quantity: 1,
              is_extra: true,
              state: 'pending',
              sequence: maxSeq + 10,
            },
          ],
        ],
      },
      id: Math.floor(Math.random() * 1e6),
    });
    if (cr.error) {
      return {
        md:
          '\n\n⚠️ **Material extra:** No pude añadir «**' +
          productoMencion +
          '**» a la tarea: ' +
          (cr.error.data?.message || cr.error.message || ''),
      };
    }
    const newId = Array.isArray(cr.result) ? cr.result[0] : cr.result;
    lineIdsMarcar = [Number(newId)].filter((id) => Number.isFinite(id) && id > 0);
  } else if (hechas.length) {
    const nombre =
      Array.isArray(hechas[0].product_id) && hechas[0].product_id[1]
        ? hechas[0].product_id[1]
        : prod.name;
    const matsReload = (await loadMaterialesTarea(db, uid, taskId)).mats;
    return {
      md:
        '\n\n✅ **Material extra:** «**' +
        nombre +
        '**» **ya estaba en la lista** de la tarea y figura como **usado**.\n\n📦 **Materiales de la tarea:**\n' +
        bullets(matsReload, prodById),
    };
  } else if (noUsadas.length) {
    return {
      md:
        '\n\n⚠️ **Material extra:** «**' +
        productoMencion +
        '**» está en la tarea como **no usado**. Revísalo en Odoo antes de registrar consumo.\n\n**Tu línea:**\n' +
        bullets(noUsadas, prodById, 10),
    };
  }

  if (!lineIdsMarcar.length) {
    return {
      md:
        '\n\n⚠️ **Material extra:** No pude registrar el consumo de «**' + productoMencion + '**».',
    };
  }

  try {
    await markUsedLineIds(db, uid, lineIdsMarcar);
  } catch (e) {
    return {
      md:
        '\n\n⚠️ **Material extra:** Añadido a la lista pero Odoo no pudo marcar consumo: ' +
        String(e.message || e),
    };
  }

  const matsReload = (await loadMaterialesTarea(db, uid, taskId)).mats;
  const eraNuevo = !lineasMismoProd.length;
  const nombreProd =
    prod.name + (prod.default_code ? ' [' + prod.default_code + ']' : '');

  return {
    md:
      '\n\n✅ **Material extra' +
      (eraNuevo ? ' añadido a la tarea' : '') +
      ' y registrado como usado**' +
      ': **' +
      nombreProd +
      '**.\n\n📦 **Materiales actuales de la tarea:**\n' +
      bullets(matsReload, prodById),
  };
}

const run = async () => {
  const x = $json || {};
  const db = x.db || 'lsanchezgoshawk-botpartesdetrabajo-main-32341811';
  const taskId = Number(x.task_id ?? x.tarea_id);
  const textoDecl = resolveTextoDeclaracion(x);

  const productoNoUsado = extractProductoNoUsado(textoDecl);
  const productoExtra = extractProductoExtraUsado(textoDecl);

  const passthrough = () => ({
    ...x,
    transcripcion_original: textoDecl || x.transcripcion_original || null,
    producto_no_usado_extraido: productoNoUsado || '',
    producto_extra_usado_extraido: productoExtra || '',
    material_validado_en_parte: false,
    material_no_usado_resumen_md: x.material_no_usado_resumen_md || '',
  });

  if (!productoNoUsado && !productoExtra) {
    return passthrough();
  }

  if (!Number.isFinite(taskId) || taskId <= 0) {
    const quien = [productoNoUsado, productoExtra].filter(Boolean).join('» / «');
    return {
      ...passthrough(),
      material_no_usado_resumen_md:
        '\n\n⚠️ **Material del parte:** No pude asociar la tarea para procesar «' + quien + '».',
      material_validado_en_parte: true,
    };
  }

  let uid;
  try {
    uid = await odooAuth(db);
  } catch (e) {
    return {
      ...passthrough(),
      material_no_usado_resumen_md: '\n\n⚠️ **Material del parte:** Error conectando con Odoo.',
      material_validado_en_parte: true,
    };
  }

  let matsAll = [];
  let moduloAusente = false;
  try {
    const loaded = await loadMaterialesTarea(db, uid, taskId);
    matsAll = loaded.mats;
    moduloAusente = loaded.moduloAusente;
  } catch (e) {
    return {
      ...passthrough(),
      material_no_usado_resumen_md:
        '\n\n⚠️ **Material del parte:** Error leyendo materiales de la tarea: ' +
        String(e.message || e),
      material_validado_en_parte: true,
    };
  }

  if (moduloAusente) {
    return {
      ...passthrough(),
      material_no_usado_resumen_md:
        '\n\n⚠️ **Material del parte:** El módulo de materiales de tarea no está disponible en Odoo.',
      material_validado_en_parte: true,
    };
  }

  const partesMd = [];

  async function prepCatalogo(mencion) {
    let prods;
    try {
      prods = await searchProductos(db, uid, mencion);
    } catch (e) {
      return { error: 'Error buscando en catálogo: ' + String(e.message || e) };
    }
    if (!prods.length) {
      return { error: 'No encuentro en catálogo ningún producto parecido a «**' + mencion + '**».' };
    }
    const prodElegido = pickProducto(prods, mencion);
    const prodById = new Map(prods.map((p) => [p.id, p]));
    const prodIdsFound = new Set(prods.map((p) => p.id));
    return { prods, prodElegido, prodById, prodIdsFound };
  }

  if (productoNoUsado) {
    const cat = await prepCatalogo(productoNoUsado);
    if (cat.error) {
      partesMd.push('\n\n⚠️ **Material (no usado):** ' + cat.error);
    } else {
      const r = await procesarNoUsado({
        db,
        uid,
        taskId,
        productoMencion: productoNoUsado,
        matsAll,
        ...cat,
      });
      partesMd.push(r.md);
    }
  }

  if (productoExtra) {
    const cat = await prepCatalogo(productoExtra);
    if (cat.error) {
      partesMd.push('\n\n⚠️ **Material extra:** ' + cat.error);
    } else {
      const r = await procesarExtraUsado({
        db,
        uid,
        taskId,
        productoMencion: productoExtra,
        matsAll,
        ...cat,
      });
      partesMd.push(r.md);
      if (r.md.includes('añadido') || r.md.includes('registrado como usado')) {
        const reloaded = await loadMaterialesTarea(db, uid, taskId);
        matsAll = reloaded.mats;
      }
    }
  }

  return {
    ...x,
    transcripcion_original: textoDecl || x.transcripcion_original || null,
    producto_no_usado_extraido: productoNoUsado || '',
    producto_extra_usado_extraido: productoExtra || '',
    material_validado_en_parte: true,
    material_no_usado_resumen_md: partesMd.join(''),
  };
};

return await run();

