  const estado = br >= 1.0 ? 'SOBREPASADO' : 'CRITICO';
  const manager = Array.isArray(t.user_ids) && t.user_ids.length > 0 ? t.user_ids.map(u => u[1]).join(', ') : 'Sin responsable';
