  alertas.push({ tarea_id: t.id, tarea_nombre: t.name, proyecto_nombre: proyecto, pedido, burn_rate_pct: pct, horas_consumidas: parseFloat(hc.toFixed(2)), horas_presupuestadas: hp, horas_restantes: parseFloat(hr.toFixed(2)), estado, manager_nombre: manager, cliente_nombre: cliente, mensaje_alerta: msg });
