const timesheets = $('Obtener Tareas CB').first().json.result || [];
const PALABRAS = ['retraso por falta', 'falta de material', 'esperando aprobacion', 'esperando planos', 'sin material', 'pendiente de', 'bloqueado', 'bloqueada', 'bloqueados', 'esperando proveedor', 'no hay stock', 'falta stock', 'esperando cliente', 'sin respuesta', 'no disponible', 'parado', 'parada', 'parados', 'esperando confirmacion', 'retrasado', 'retrasada', 'en espera', 'aplazado', 'llevamos esperando', 'llevamos parados', 'seguimos esperando', 'dias esperando', 'semanas esperando', 'no podemos avanzar', 'sin poder avanzar', 'no avanzamos'];
const norm = s => String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
const map = {};
for (const ts of timesheets) {
  const desc = norm(ts.name || '');
  const pid = ts.project_id ? ts.project_id[0] : null;
  if (!pid) continue;
  for (const p of PALABRAS) {
    if (desc.includes(norm(p))) {
      if (!map[pid]) map[pid] = { proyecto_id: pid, proyecto_nombre: ts.project_id[1], ocurrencias: 0, horas: 0, empleados: new Set(), palabras: new Set(), ejemplos: [] };
      map[pid].ocurrencias++;
      map[pid].horas += ts.unit_amount || 0;
      if (ts.employee_id) map[pid].empleados.add(ts.employee_id[1]);
      map[pid].palabras.add(p);
      if (map[pid].ejemplos.length < 3) map[pid].ejemplos.push((ts.name || '').substring(0, 80));
      break;
    }
  }
}
const cuellos = Object.values(map).filter(c => c.ocurrencias >= 1).map(c => ({ ...c, empleados: Array.from(c.empleados), palabras: Array.from(c.palabras), horas: parseFloat(c.horas.toFixed(2)) }));
